      function setConnStatus(status, attempt) {
        void status;
        void attempt;
      }

      /** توقيت المنصة الرسمي — المملكة العربية السعودية */
      const APP_TZ = 'Asia/Riyadh';
      const KSA_TZ_OFFSET = '+03:00';
      const KSA_CLOCK_RESYNC_MS = 10 * 60 * 1000;
      const KSA_CLOCK_FETCH_TIMEOUT_MS = 8000;

      /** فرق الميلي ثانية بين ساعة الجهاز ووقت الرياض الحقيقي (يُحدَّث من الإنترنت فقط) */
      function ksaClockReady() {
        return !!(state._ksaClockSynced && Number.isFinite(state._ksaClockOffsetMs));
      }

      function ksaNowMs() {
        if (!ksaClockReady()) return NaN;
        return Date.now() + state._ksaClockOffsetMs;
      }

      /** اللحظة الحالية بتوقيت الرياض — لا تُستخدم ساعة الجهاز مباشرة */
      function ksaNow() {
        const ms = ksaNowMs();
        if (!Number.isFinite(ms)) return null;
        return new Date(ms);
      }

      async function fetchKsaClockOffsetTimeApiIo(signal) {
        const t0 = Date.now();
        const res = await fetch('https://timeapi.io/api/Time/current/zone?timeZone=Asia/Riyadh', { signal, cache: 'no-store' });
        if (!res.ok) throw new Error(`timeapi.io ${res.status}`);
        const data = await res.json();
        const t1 = Date.now();
        const serverMs = new Date(
          `${data.year}-${ksaPad(data.month)}-${ksaPad(data.day)}T` +
          `${ksaPad(data.hour)}:${ksaPad(data.minute)}:${ksaPad(data.seconds ?? 0)}${KSA_TZ_OFFSET}`
        ).getTime();
        if (!Number.isFinite(serverMs)) throw new Error('timeapi.io parse');
        return serverMs + (t1 - t0) / 2 - t1;
      }

      async function fetchKsaClockOffsetHttpDate(url, signal) {
        const t0 = Date.now();
        const res = await fetch(url, { method: 'HEAD', signal, cache: 'no-store', mode: 'cors' });
        const t1 = Date.now();
        const hdr = res.headers.get('date');
        if (!hdr) throw new Error('no date header');
        const serverMs = new Date(hdr).getTime();
        if (!Number.isFinite(serverMs)) throw new Error('date header parse');
        return serverMs + (t1 - t0) / 2 - t1;
      }

      async function syncKsaClockOffset() {
        const origin = (typeof window !== 'undefined' && window.location?.origin) ? window.location.origin : '';
        const sources = [
          fetchKsaClockOffsetTimeApiIo,
          (signal) => fetchKsaClockOffsetHttpDate('https://api.github.com', signal),
        ];
        if (origin && !/^file:/i.test(origin)) {
          sources.unshift((signal) => fetchKsaClockOffsetHttpDate(`${origin}/`, signal));
        }
        let lastErr = null;
        for (const source of sources) {
          const ctrl = new AbortController();
          const timer = window.setTimeout(() => ctrl.abort(), KSA_CLOCK_FETCH_TIMEOUT_MS);
          try {
            const offset = await source(ctrl.signal);
            window.clearTimeout(timer);
            if (!Number.isFinite(offset)) continue;
            state._ksaClockOffsetMs = offset;
            state._ksaClockSynced = true;
            state._ksaClockSyncedAt = Date.now();
            if (isMirsadDebugLog()) console.log('[KsaClock] synced offset ms:', Math.round(offset));
            return true;
          } catch (e) {
            lastErr = e;
            window.clearTimeout(timer);
          }
        }
        if (isMirsadDebugLog()) console.warn('[KsaClock] sync failed', lastErr);
        return false;
      }

      async function ensureKsaClockSynced(maxAttempts = 5) {
        for (let i = 0; i < maxAttempts; i++) {
          if (await syncKsaClockOffset()) return true;
          await new Promise((r) => window.setTimeout(r, 1200 * (i + 1)));
        }
        return false;
      }

      function armKsaClockResync() {
        if (state._ksaClockResyncTimer) return;
        state._ksaClockResyncTimer = window.setInterval(() => {
          if (document.hidden) return;
          syncKsaClockOffset();
        }, KSA_CLOCK_RESYNC_MS);
      }

      function armKsaClockRetryUntilSynced() {
        if (state._ksaClockRetryTimer || ksaClockReady()) return;
        state._ksaClockRetryTimer = window.setInterval(async () => {
          if (await syncKsaClockOffset()) {
            window.clearInterval(state._ksaClockRetryTimer);
            state._ksaClockRetryTimer = null;
          }
        }, 8000);
      }

      async function initKsaClockSync() {
        armKsaClockResync();
        const ok = await ensureKsaClockSynced(5);
        if (!ok) armKsaClockRetryUntilSynced();
        return ok;
      }

      function ksaPad(n) {
        return String(n).padStart(2, '0');
      }

      function ksaFormatParts(date = null) {
        const d = date == null ? ksaNow() : (date instanceof Date ? date : new Date(date));
        if (!d || isNaN(d.getTime())) return null;
        const map = {};
        new Intl.DateTimeFormat('en-US', {
          timeZone: APP_TZ,
          year: 'numeric',
          month: '2-digit',
          day: '2-digit',
          hour: '2-digit',
          minute: '2-digit',
          second: '2-digit',
          hour12: false
        }).formatToParts(d).forEach(p => {
          if (p.type !== 'literal') map[p.type] = p.value;
        });
        return {
          year: +map.year,
          month: +map.month - 1,
          day: +map.day,
          hour: +map.hour,
          minute: +map.minute,
          second: +map.second
        };
      }

      function ksaShiftMonth(year, month0, delta) {
        let m = month0 + delta, y = year;
        while (m < 0) { m += 12; y--; }
        while (m > 11) { m -= 12; y++; }
        return { year: y, month: m };
      }

      function ksaMonthRange(year, month0) {
        const lastDay = ksaDaysInCalendarMonth(year, month0);
        return {
          fromIso: `${year}-${ksaPad(month0 + 1)}-01`,
          toIso: `${year}-${ksaPad(month0 + 1)}-${ksaPad(lastDay)}`,
          daysInMonth: lastDay,
          year,
          month: month0
        };
      }

      function ksaCurrentMonthRange() {
        const p = ksaFormatParts();
        if (!p) {
          return {
            fromIso: '',
            toIso: '',
            daysInMonth: 0,
            year: 0,
            month: 0,
            nextFromIso: '',
            monthStart: null,
            nextMonthStart: null
          };
        }
        const cur = ksaMonthRange(p.year, p.month);
        const next = ksaShiftMonth(p.year, p.month, 1);
        const nextR = ksaMonthRange(next.year, next.month);
        return {
          ...cur,
          nextFromIso: nextR.fromIso,
          monthStart: ksaCalendarDate(p.year, p.month, 1),
          nextMonthStart: ksaCalendarDate(next.year, next.month, 1)
        };
      }

      function ksaMonthSlots(count) {
        const p = ksaFormatParts();
        if (!p) return [];
        const out = [];
        for (let i = count - 1; i >= 0; i--) {
          const { year, month } = ksaShiftMonth(p.year, p.month, -i);
          out.push({
            year,
            month,
            monthName: KSA_AR_MONTHS[month],
            yearLabel: String(year)
          });
        }
        return out;
      }

      function ksaFormatDateTime(dateInput) {
        if (!dateInput) return '-';
        try {
          const d = dateInput instanceof Date ? dateInput : new Date(dateInput);
          if (isNaN(d.getTime())) return String(dateInput);
          const p = ksaFormatParts(d);
          const h12 = p.hour % 12 || 12;
          const ampm = p.hour >= 12 ? 'م' : 'ص';
          return `${p.year}-${ksaPad(p.month + 1)}-${ksaPad(p.day)} ${h12}:${ksaPad(p.minute)} ${ampm}`;
        } catch {
          return String(dateInput);
        }
      }

      function ksaIsoInMonth(iso, year, month0) {
        if (!iso || iso.length < 7) return false;
        const y = +iso.slice(0, 4);
        const m = +iso.slice(5, 7) - 1;
        return y === year && m === month0;
      }

      function ksaTodayIso() {
        const p = ksaFormatParts();
        if (!p) return '';
        return `${p.year}-${ksaPad(p.month + 1)}-${ksaPad(p.day)}`;
      }

      function ksaParseIso(iso) {
        const m = /^(\d{4})-(\d{2})-(\d{2})/.exec(String(iso || '').trim());
        if (!m) return null;
        return { year: +m[1], month: +m[2] - 1, day: +m[3] };
      }

      function ksaCalendarDate(year, month0, day) {
        return new Date(`${year}-${ksaPad(month0 + 1)}-${ksaPad(day)}T12:00:00${KSA_TZ_OFFSET}`);
      }

      function ksaTodayCalendar() {
        const p = ksaFormatParts();
        if (!p) return null;
        return ksaCalendarDate(p.year, p.month, p.day);
      }

      function ksaDateFromIso(iso) {
        const p = ksaParseIso(iso);
        return p ? ksaCalendarDate(p.year, p.month, p.day) : null;
      }

      function ksaCalendarToIso(d) {
        if (!(d instanceof Date) || isNaN(d.getTime())) return '';
        const p = ksaFormatParts(d);
        if (!p) return '';
        return `${p.year}-${ksaPad(p.month + 1)}-${ksaPad(p.day)}`;
      }

      function ksaSameCalendarDay(a, b) {
        if (!a || !b) return false;
        const ia = a instanceof Date ? ksaCalendarToIso(a) : String(a).slice(0, 10);
        const ib = b instanceof Date ? ksaCalendarToIso(b) : String(b).slice(0, 10);
        return !!(ia && ib && ia === ib);
      }

      function ksaInitViewState(st) {
        const p = ksaFormatParts();
        if (!p) return;
        st.viewYear = p.year;
        st.viewMonth = p.month;
      }

      function ksaDaysInCalendarMonth(year, month0) {
        return new Date(Date.UTC(year, month0 + 1, 0)).getUTCDate();
      }

      function ksaMonthCalendarBounds(year, month0) {
        const last = ksaDaysInCalendarMonth(year, month0);
        return {
          from: ksaCalendarDate(year, month0, 1),
          to: ksaCalendarDate(year, month0, last)
        };
      }

      function ksaWeekdayIndex(year, month0, day) {
        const wd = new Date(Date.UTC(year, month0, day, 12, 0, 0))
          .toLocaleDateString('en-US', { timeZone: APP_TZ, weekday: 'short' });
        const map = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
        return map[wd] ?? 0;
      }

      function ksaShiftCalendarDays(year, month0, day, delta) {
        const anchor = new Date(`${year}-${ksaPad(month0 + 1)}-${ksaPad(day)}T12:00:00${KSA_TZ_OFFSET}`);
        const p = ksaFormatParts(new Date(anchor.getTime() + delta * 86400000));
        if (!p) return { year, month: month0, day };
        return { year: p.year, month: p.month, day: p.day };
      }

      function ksaThisWeekRange() {
        const p = ksaFormatParts();
        return ksaWeekRangeForCalendarDate(p.year, p.month, p.day);
      }

      function ksaWeekRangeForCalendarDate(year, month0, day) {
        const wd = ksaWeekdayIndex(year, month0, day);
        const s = ksaShiftCalendarDays(year, month0, day, -wd);
        const e = ksaShiftCalendarDays(s.year, s.month, s.day, 6);
        return {
          from: ksaCalendarDate(s.year, s.month, s.day),
          to: ksaCalendarDate(e.year, e.month, e.day)
        };
      }

      const KSA_AR_MONTHS = [
        'يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو',
        'يوليو', 'أغسطس', 'سبتمبر', 'أكتوبر', 'نوفمبر', 'ديسمبر'
      ];
      const KSA_AR_WEEKDAYS = ['الأحد', 'الإثنين', 'الثلاثاء', 'الأربعاء', 'الخميس', 'الجمعة', 'السبت'];

      function formatDashMonthYear(year, month0) {
        return `${KSA_AR_MONTHS[month0]} ${year}`;
      }

      /** عنوان فرعي للوحة القيادة حسب دور المستخدم */
      function getDashWelcomeSubtitle(role, monthLbl) {
        const r = normalizeUserRole(role);
        const suffix = ` · ${monthLbl}`;
        const byRole = {
          employee: `إليك نظرة عامة على أدائك لشهر${suffix}`,
          branch_manager: `إليك نظرة عامة على أدائك وأداء فريقك لشهر${suffix}`,
          supervisor: `إليك نظرة عامة على أداء منطقتك لشهر${suffix}`,
          admin: `إليك نظرة عامة على أداء المناطق لشهر${suffix}`,
          manager: `إليك نظرة عامة على أداء المناطق لشهر${suffix}`,
          hr: `إليك نظرة عامة على تذاكر الموارد البشرية لشهر${suffix}`,
          observer: `إليك نظرة عامة على أداء رصدك لشهر${suffix}`
        };
        return byRole[r] || `إليك نظرة عامة على أداء منصتك لشهر${suffix}`;
      }

      /** تاريخ عربي ميلادي — يتجنب تقويم أم القرى على iOS/جوال */
      function ksaLocaleDateAr(value, options = {}) {
        const iso = typeof value === 'string' ? value.slice(0, 10) : ksaCalendarToIso(value);
        if (!iso) return '-';
        try {
          return new Date(iso + 'T12:00:00').toLocaleDateString('ar-SA-u-ca-gregory-u-nu-latn', {
            timeZone: APP_TZ,
            calendar: 'gregory',
            numberingSystem: 'latn',
            ...options
          });
        } catch {
          return iso;
        }
      }

      /** تاريخ لوحة القيادة — الجمعة · 22 مايو 2026 (توقيت الرياض) */
      function formatDashHeroDate(dateInput) {
        let y, m, day;
        if (dateInput == null) {
          const p = ksaFormatParts(ksaNow());
          if (!p) return '—';
          y = p.year; m = p.month; day = p.day;
        } else if (dateInput instanceof Date) {
          const p = ksaFormatParts(dateInput);
          if (!p) return '—';
          y = p.year; m = p.month; day = p.day;
        } else {
          const p = ksaParseIso(dateInput);
          if (!p) return '—';
          y = p.year; m = p.month; day = p.day;
        }
        const wd = KSA_AR_WEEKDAYS[ksaWeekdayIndex(y, m, day)] || '';
        return `${wd} · ${day} ${KSA_AR_MONTHS[m]} ${y}`;
      }

      function updateDashDateKicker() {
        const dk = document.getElementById('dash-date-kicker');
        if (dk) dk.textContent = formatDashHeroDate(null);
      }

      /** ساعة الشريط العلوي — وقت وتاريخ حي بتوقيت الرياض */
      function formatKsaLiveClock(now) {
        const d = now ?? ksaNow();
        if (!d || isNaN(d.getTime())) {
          return { hm: '--:--', ampm: '', dateLine: 'جاري مزامنة وقت الرياض…' };
        }
        const p = ksaFormatParts(d);
        if (!p) return { hm: '--:--', ampm: '', dateLine: 'جاري مزامنة وقت الرياض…' };
        const h12 = p.hour % 12 || 12;
        const ampm = p.hour >= 12 ? 'م' : 'ص';
        const wd = KSA_AR_WEEKDAYS[ksaWeekdayIndex(p.year, p.month, p.day)] || '';
        return {
          hm: `${ksaPad(h12)}:${ksaPad(p.minute)}`,
          ampm,
          dateLine: `${wd} · ${p.day} ${KSA_AR_MONTHS[p.month]} ${p.year}`
        };
      }

      function ksaCsvDateStamp() {
        return ksaTodayIso();
      }

      function ksaIsoFromMs(ms) {
        const p = ksaFormatParts(new Date(ms));
        return `${p.year}-${ksaPad(p.month + 1)}-${ksaPad(p.day)}`;
      }

      function ksaEndOfIsoDayMs(iso) {
        const p = ksaParseIso(iso);
        if (!p) return ksaClockReady() ? ksaNowMs() : NaN;
        const d = new Date(`${iso}T23:59:59.999+03:00`);
        return isNaN(d.getTime()) ? (ksaClockReady() ? ksaNowMs() : NaN) : d.getTime();
      }

      function getNow() {
        const p = ksaFormatParts();
        if (!p) return '';
        return `${p.year}-${ksaPad(p.month + 1)}-${ksaPad(p.day)} ${ksaPad(p.hour)}:${ksaPad(p.minute)}`;
      }

      // عرض التاريخ والوقت بصيغة 12 ساعة مع ص/م (توقيت الرياض)
      function formatDateTime(s) {
        return ksaFormatDateTime(s);
      }

      // تحويل وقت بصيغة "HH:MM" إلى 12 ساعة مع ص/م
      function formatTime12(timeStr) {
        if (!timeStr) return '-';
        try {
          // قد تأتي بصيغة HH:MM أو HH:MM:SS
          const parts = String(timeStr).split(':');
          if (parts.length < 2) return timeStr;
          const h = parseInt(parts[0], 10);
          const m = parts[1].padStart(2, '0');
          if (isNaN(h)) return timeStr;
          const ampm = h >= 12 ? 'م' : 'ص';
          const h12 = h % 12 || 12;
          return `${ampm} ${h12}:${m}`;
        } catch { return timeStr; }
      }

      /** وقت الجوال وسطح المكتب: ص/م على الجهة الأخرى من الساعة */
      function formatMobTicketTimeHtml(timeStr) {
        if (!timeStr) return '-';
        try {
          const parts = String(timeStr).split(':');
          if (parts.length < 2) return Sec.escapeHTML(timeStr);
          const h = parseInt(parts[0], 10);
          const m = String(parts[1] || '0').padStart(2, '0').slice(0, 2);
          if (isNaN(h)) return Sec.escapeHTML(timeStr);
          const ampm = h >= 12 ? 'م' : 'ص';
          const h12 = h % 12 || 12;
          return `<span class="wf-time-hm" dir="ltr">${Sec.escapeHTML(h12 + ':' + m)}</span><span class="wf-time-ampm">${Sec.escapeHTML(ampm)}</span>`;
        } catch {
          return Sec.escapeHTML(timeStr);
        }
      }

      /** 12 ساعة مع ص/م قبل الساعة — لعرض نموذج رصد المخالفة */
      function formatTime12AmFirst(timeStr) {
        if (!timeStr) return '';
        try {
          const parts = String(timeStr).split(':');
          if (parts.length < 2) return timeStr;
          const h = parseInt(parts[0], 10);
          const m = parts[1].padStart(2, '0');
          if (isNaN(h)) return timeStr;
          const ampm = h >= 12 ? 'م' : 'ص';
          const h12 = h % 12 || 12;
          return `${ampm} ${h12}:${m}`;
        } catch { return timeStr; }
      }

      // تنسيق وقت سجل (date string من logs أو timestamp)
      function formatLogDate(s) {
        return formatDateTime(s);
      }

      // حساب الفرق بالساعات بين وقت معين والآن
      function hoursSince(dateStr) {
        if (!dateStr) return 0;
        try {
          const d = new Date(dateStr);
          if (isNaN(d.getTime())) return 0;
          return (Date.now() - d.getTime()) / (1000 * 60 * 60);
        } catch { return 0; }
      }

      // حساب الوقت المتبقي قبل التمرير التلقائي
      function timeRemaining(dateStr, limitHours) {
        const passed = hoursSince(dateStr);
        const remaining = Math.max(0, limitHours - passed);
        if (remaining < 1) {
          const mins = Math.floor(remaining * 60);
          return `${mins} دقيقة`;
        }
        return `${Math.floor(remaining)} ساعة`;
      }

      // ═══════════════════════════════════════════════════════════════════════════
      // 6. THEME
      // ═══════════════════════════════════════════════════════════════════════════
      function syncThemeMetaColor(theme) {
        const meta = document.getElementById('metaThemeColor');
        if (theme) document.documentElement.setAttribute('data-theme', theme);
        const active = theme || document.documentElement.getAttribute('data-theme') || 'light';
        if (meta) meta.setAttribute('content', active === 'dark' ? '#1c1c21' : '#f5f5f7');
      }

      function themeToggleMoonSvg(className, colorClass) {
        return `<svg class="theme-toggle__icon ${className} ${colorClass}" xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 3a6 6 0 0 0 9 9 9 9 0 1 1-9-9Z"/></svg>`;
      }

      function themeToggleSunSvg(className, colorClass) {
        return `<svg class="theme-toggle__icon ${className} ${colorClass}" xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="4"/><path d="M12 2v2"/><path d="M12 20v2"/><path d="m4.93 4.93 1.41 1.41"/><path d="m17.66 17.66 1.41 1.41"/><path d="M2 12h2"/><path d="M20 12h2"/><path d="m6.34 17.66-1.41 1.41"/><path d="m19.07 4.93-1.41 1.41"/></svg>`;
      }

      function syncThemeToggleUi(theme) {
        const active = theme || document.documentElement.getAttribute('data-theme') || 'light';
        const isDark = active === 'dark';
        const el = document.getElementById('topbarThemeToggle');
        const knob = document.getElementById('themeToggleKnob');
        const ghost = document.getElementById('themeToggleGhost');
        if (el) {
          el.classList.toggle('theme-toggle--dark', isDark);
          el.classList.toggle('theme-toggle--light', !isDark);
          el.setAttribute('aria-pressed', isDark ? 'true' : 'false');
        }
        if (knob && ghost) {
          if (isDark) {
            knob.innerHTML = themeToggleMoonSvg('', 'theme-toggle__icon--on-dark');
            ghost.innerHTML = themeToggleSunSvg('', 'theme-toggle__icon--muted');
          } else {
            knob.innerHTML = themeToggleSunSvg('', 'theme-toggle__icon--on-light-knob');
            ghost.innerHTML = themeToggleMoonSvg('', 'theme-toggle__icon--on-light-ghost');
          }
        }
      }

      function syncTopbarUserMenuTheme() {
        syncThemeToggleUi();
      }

      function closeTopbarUserMenu() { /* legacy — القائمة أُزيلت لصالح صفحة البروفايل */ }

      function toggleTopbarUserMenu(event) {
        openProfilePage(event);
      }

      function toggleThemeFromUserMenu(event) {
        if (event) event.stopPropagation();
        toggleTheme();
      }

      async function handleLogoutFromUserMenu(event) {
        if (event) event.stopPropagation();
        await handleLogout();
      }

      function refreshWefaqLogosForTheme() {
        /* الشعار يستخدم currentColor — لا حاجة لإعادة الرسم عند تبديل الثيم */
      }

      function toggleTheme(event) {
        if (event) event.stopPropagation();
        const html = document.documentElement;
        const cur = html.getAttribute('data-theme') || 'light';
        const next = cur === 'light' ? 'dark' : 'light';
        html.setAttribute('data-theme', next);
        localStorage.setItem('mp_theme', next);
        syncThemeMetaColor(next);
        syncTopbarUserMenuTheme();
        refreshWefaqLogosForTheme();
      }

      function loadTheme() {
        const saved = localStorage.getItem('mp_theme') || 'light';
        document.documentElement.setAttribute('data-theme', saved);
        syncThemeMetaColor(saved);
        syncTopbarUserMenuTheme();
        refreshWefaqLogosForTheme();
      }

      // ─── ساعة حية في الـ topbar (توقيت الرياض من الإنترنت — 12 ساعة + تاريخ عربي) ───
      function startLiveClock() {
        const timeEl = document.getElementById('clockText');
        const ampmEl = document.getElementById('clockAmPm');
        const dateEl = document.getElementById('clockDate');
        if (!timeEl || !ampmEl || !dateEl) return;
        const update = () => {
          const clock = formatKsaLiveClock();
          timeEl.textContent = clock.hm;
          ampmEl.textContent = clock.ampm;
          dateEl.textContent = clock.dateLine;
          if (ksaClockReady() && document.getElementById('tab-dashboard')?.classList.contains('active')) {
            updateDashDateKicker();
          }
        };
        update();
        if (state._clockTimer) clearInterval(state._clockTimer);
        state._clockTimer = setInterval(update, 1000);
      }

      function handleGlobalTopSearch(q) {
        const query = String(q || '').trim().toLowerCase();
        const wf = document.getElementById('tab-workflow');
        if (wf && wf.classList.contains('active')) {
          const wfInput = document.getElementById('wf-search');
          if (wfInput && wfInput.value !== q) {
            wfInput.value = q;
            if (typeof filterTickets === 'function') filterTickets();
          }
          return;
        }
        if (!query) return;
        if (typeof goTab === 'function') {
          goTab('workflow', document.querySelector('.nav-item[onclick*="workflow"]'));
          const wfInput = document.getElementById('wf-search');
          if (wfInput) {
            wfInput.value = q;
            if (typeof filterTickets === 'function') filterTickets();
          }
        }
      }

      // ═══════════════════════════════════════════════════════════════════════════
      // 7. AUTHENTICATION
      // ═══════════════════════════════════════════════════════════════════════════

      function isMobileLandscapeViewport() {
        if (typeof isMobileViewport === 'function' && !isMobileViewport()) return false;
        if (!window.matchMedia('(orientation: landscape)').matches) return false;
        return Math.min(window.innerWidth, window.innerHeight) < 520;
      }

      function lockMobilePortraitOrientation() {
        if (typeof isMobileViewport === 'function' && !isMobileViewport()) return;
        const orient = screen.orientation;
        if (!orient || typeof orient.lock !== 'function') return;
        orient.lock('portrait-primary').catch(() => {
          orient.lock('portrait').catch(() => {});
        });
      }

      function syncMobilePortraitLock() {
        const locked = isMobileLandscapeViewport();
        document.documentElement.classList.toggle('mob-landscape-locked', locked);
        const overlay = document.getElementById('mobPortraitLock');
        if (overlay) {
          overlay.hidden = !locked;
          overlay.setAttribute('aria-hidden', locked ? 'false' : 'true');
        }
        if (!locked) lockMobilePortraitOrientation();
      }

      function setNativeAppShellActive(active) {
        const on = !!active && typeof isMobileViewport === 'function' && isMobileViewport();
        document.body.classList.toggle('mirsad-app-active', on);
        document.documentElement.classList.toggle('mirsad-app-shell-lock', on);
        if (on) {
          if (typeof syncLoginStandalonePwaClass === 'function') syncLoginStandalonePwaClass();
          if (typeof syncWefaqBranding === 'function') syncWefaqBranding();
        }
        syncMobilePortraitLock();
      }

      function initNativeAppFeel() {
        if (window._mrNativeFeelBound) return;
        window._mrNativeFeelBound = true;
        syncMobilePortraitLock();
        const tryLockOnGesture = () => {
          lockMobilePortraitOrientation();
          document.removeEventListener('touchstart', tryLockOnGesture, true);
          document.removeEventListener('click', tryLockOnGesture, true);
        };
        document.addEventListener('touchstart', tryLockOnGesture, { capture: true, passive: true });
        document.addEventListener('click', tryLockOnGesture, { capture: true, passive: true });
        const blockGestureZoom = (e) => {
          if (!document.body.classList.contains('mirsad-app-active')) return;
          e.preventDefault();
        };
        ['gesturestart', 'gesturechange', 'gestureend'].forEach((ev) => {
          document.addEventListener(ev, blockGestureZoom, { passive: false });
        });
        let lastTouchEnd = 0;
        document.addEventListener('touchend', (e) => {
          if (!document.body.classList.contains('mirsad-app-active')) return;
          const now = Date.now();
          if (now - lastTouchEnd < 320) e.preventDefault();
          lastTouchEnd = now;
        }, { passive: false });
        window.addEventListener('orientationchange', () => {
          setTimeout(syncMobilePortraitLock, 80);
        }, { passive: true });
        document.addEventListener('visibilitychange', () => {
          if (!document.hidden) syncMobilePortraitLock();
        }, { passive: true });
      }

      let _loginPortalScrollY = 0;
      let _loginVvRaf = 0;
      let _loginLockedVpH = 0;
      let _loginPortalThemeColorSaved = '';

      function syncLoginPortalChromePaint() {
        const meta = document.getElementById('metaThemeColor');
        if (!meta) return;
        const on = document.body.classList.contains('login-portal-open');
        if (on) {
          if (!_loginPortalThemeColorSaved) _loginPortalThemeColorSaved = meta.getAttribute('content') || '';
          const loginTheme = document.documentElement.getAttribute('data-theme') || 'light';
          meta.setAttribute('content', loginTheme === 'dark' ? '#1c1c21' : '#f5f5f7');
        } else if (_loginPortalThemeColorSaved) {
          meta.setAttribute('content', _loginPortalThemeColorSaved);
          _loginPortalThemeColorSaved = '';
        } else {
          syncThemeMetaColor();
        }
      }

      function isLoginMobileViewport() {
        if (document.documentElement.classList.contains('mr-mobile-ui')) return true;
        if (window.innerWidth <= 992) return true;
        try {
          return window.matchMedia('(hover: none) and (pointer: coarse)').matches;
        } catch (_) {
          return false;
        }
      }

      /** قياس منطقة home indicator — iOS PWA يُرجع env(safe-area)=0 أحياناً */
      function probeLoginSafeBottom() {
        let bottom = 0;
        try {
          const probe = document.createElement('div');
          probe.style.cssText = 'position:fixed;visibility:hidden;pointer-events:none;padding-bottom:constant(safe-area-inset-bottom);padding-bottom:env(safe-area-inset-bottom)';
          (document.body || document.documentElement).appendChild(probe);
          bottom = parseFloat(getComputedStyle(probe).paddingBottom) || 0;
          probe.remove();
        } catch (_) { /* noop */ }
        if (bottom < 1 && isLoginMobileViewport()) {
          const screenH = window.screen?.height || 0;
          const innerH = window.innerHeight || 0;
          if (screenH > 0 && innerH > 0) {
            bottom = Math.max(0, Math.round(screenH - innerH));
          }
        }
        if (bottom < 1 && isLoginStandalonePwa()) bottom = 34;
        if (isLoginStandalonePwa()) bottom = Math.max(bottom, 34);
        else if (isLoginMobileViewport()) bottom = Math.max(bottom, 20);
        const px = `${Math.max(0, Math.round(bottom))}px`;
        document.documentElement.style.setProperty('--login-safe-bottom', px);
        return bottom;
      }

      function syncLoginScreenFloor() {
        const floor = document.getElementById('loginScreenFloor');
        if (!floor) return;
        const on = document.body.classList.contains('login-portal-open') && isLoginMobileViewport();
        if (on) {
          floor.removeAttribute('hidden');
          floor.setAttribute('aria-hidden', 'true');
        } else {
          floor.setAttribute('hidden', '');
          floor.setAttribute('aria-hidden', 'true');
        }
      }

      function getLoginLayoutHeight() {
        const vv = window.visualViewport;
        const candidates = [
          _loginLockedVpH,
          window.innerHeight,
          document.documentElement.clientHeight,
          vv ? Math.round(vv.height + vv.offsetTop) : 0,
          window.screen?.height || 0
        ].filter((n) => n > 0);
        return Math.max(...candidates, 1);
      }

      function clearLoginScreenPin() {
        const ls = document.getElementById('loginScreen');
        if (!ls) return;
        ls.style.removeProperty('top');
        ls.style.removeProperty('left');
        ls.style.removeProperty('right');
        ls.style.removeProperty('bottom');
        ls.style.removeProperty('width');
        ls.style.removeProperty('height');
        ls.style.removeProperty('min-height');
        ls.style.removeProperty('max-height');
        ls.style.removeProperty('overflow');
        ls.style.removeProperty('position');
      }

      /** عند الكيبورد فقط: تثبيت بـ visualViewport — بدون كيبورد يعتمد CSS على inset:0 */
      function applyLoginScreenPin() {
        if (!document.body.classList.contains('login-portal-open')) return;
        if (!isLoginMobileViewport()) return;
        const ls = document.getElementById('loginScreen');
        if (!ls) return;
        const vv = window.visualViewport;
        const kbOpen = isLoginKeyboardOpen();

        if (vv && kbOpen) {
          const h = Math.max(1, Math.round(vv.height));
          const top = Math.max(0, Math.round(vv.offsetTop));
          ls.style.position = 'fixed';
          ls.style.top = `${top}px`;
          ls.style.left = '0';
          ls.style.right = '0';
          ls.style.bottom = 'auto';
          ls.style.width = '100%';
          ls.style.height = `${h}px`;
          ls.style.minHeight = `${h}px`;
          ls.style.maxHeight = `${h}px`;
          ls.style.overflow = 'hidden';
        } else {
          clearLoginScreenPin();
          ls.style.overflow = 'hidden';
        }
      }

      function applyLoginStableViewport() {
        const vv = window.visualViewport;
        const candidates = [
          window.innerHeight,
          document.documentElement.clientHeight,
          vv ? Math.round(vv.height + vv.offsetTop) : 0
        ].filter((n) => n > 0);
        const h = Math.max(...candidates, _loginLockedVpH || 0);
        _loginLockedVpH = h;
        syncLoginViewportLayout();
      }

      function refreshLoginStableViewportAfterKeyboard() {
        if (!document.body.classList.contains('login-portal-open')) return;
        if (!isLoginMobileViewport()) return;
        if (isLoginKeyboardOpen()) return;
        const vv = window.visualViewport;
        const candidates = [
          window.innerHeight,
          document.documentElement.clientHeight,
          vv ? Math.round(vv.height + vv.offsetTop) : 0
        ].filter((n) => n > 0);
        const h = Math.max(...candidates);
        if (h > 0) _loginLockedVpH = h;
        syncLoginViewportLayout();
      }

      function clearLoginStableViewport() {
        _loginLockedVpH = 0;
      }

      function clearLoginPortalViewportState() {
        clearLoginStableViewport();
        const root = document.documentElement;
        root.style.removeProperty('--login-vp-h');
        root.style.removeProperty('--login-vp-top');
        root.style.removeProperty('--login-card-shift');
        root.style.removeProperty('--login-safe-bottom');
        document.body.classList.remove('login-keyboard-open');
        clearLoginScreenPin();
        syncLoginScreenFloor();
      }

      function getLoginKeyboardInset() {
        const vv = window.visualViewport;
        if (!vv) return 0;
        const layoutH = _loginLockedVpH || window.innerHeight || document.documentElement.clientHeight || 0;
        return Math.max(0, Math.round(layoutH - vv.offsetTop - vv.height));
      }

      function isLoginKeyboardOpen() {
        return getLoginKeyboardInset() > 72;
      }

      /** تثبيت أبعاد شاشة الدخول — CSS inset:0 بدون كيبورد، vv فقط عند الكيبورد */
      function syncLoginViewportLayout() {
        if (!document.body.classList.contains('login-portal-open')) return;
        if (!isLoginMobileViewport()) return;
        probeLoginSafeBottom();
        syncLoginScreenFloor();
        const root = document.documentElement;
        const vv = window.visualViewport;
        const kbOpen = isLoginKeyboardOpen();

        if (vv && kbOpen) {
          const h = Math.max(1, Math.round(vv.height));
          const top = Math.max(0, Math.round(vv.offsetTop));
          root.style.setProperty('--login-vp-h', `${h}px`);
          root.style.setProperty('--login-vp-top', `${top}px`);
        } else {
          root.style.removeProperty('--login-vp-h');
          root.style.removeProperty('--login-vp-top');
        }
        document.body.classList.toggle('login-keyboard-open', kbOpen);
        applyLoginScreenPin();
        window.scrollTo(0, 0);
      }

      function resetLoginCardShift() {
        document.documentElement.style.setProperty('--login-card-shift', '0px');
      }

      /** إزاحة البطاقة فقط — بدون سكرول الصفحة */
      function scrollLoginFieldIntoView(field) {
        if (!field?.closest?.('#loginCard')) return;
        if (!isLoginMobileViewport()) return;

        const run = () => {
          syncLoginViewportLayout();
          const vv = window.visualViewport;
          if (!vv) return;
          const gap = 14;
          const rect = field.getBoundingClientRect();
          const visibleTop = vv.offsetTop;
          const visibleBottom = vv.offsetTop + vv.height;
          let shift = 0;
          if (rect.bottom > visibleBottom - gap) {
            shift = rect.bottom - (visibleBottom - gap);
          } else if (rect.top < visibleTop + gap) {
            shift = -(visibleTop + gap - rect.top);
          }
          document.documentElement.style.setProperty('--login-card-shift', `${-Math.round(shift)}px`);
        };

        requestAnimationFrame(run);
        setTimeout(run, 48);
        setTimeout(run, 280);
      }

      function scheduleLoginFieldScroll(field) {
        if (!field) return;
        if (_loginVvRaf) cancelAnimationFrame(_loginVvRaf);
        _loginVvRaf = requestAnimationFrame(() => {
          _loginVvRaf = 0;
          scrollLoginFieldIntoView(field);
        });
      }

      function resetLoginScreenScrollIfKeyboardClosed() {
        if (!document.body.classList.contains('login-portal-open')) return;
        if (!isLoginMobileViewport()) return;
        if (isLoginKeyboardOpen()) return;
        if (document.activeElement?.closest?.('#loginCard input, #loginCard textarea, #loginCard select')) return;
        refreshLoginStableViewportAfterKeyboard();
        resetLoginCardShift();
        const ls = document.getElementById('loginScreen');
        if (ls) ls.scrollTop = 0;
        window.scrollTo(0, 0);
      }

      function isLoginStandalonePwa() {
        return !!(
          window.navigator.standalone ||
          window.matchMedia('(display-mode: standalone)').matches ||
          window.matchMedia('(display-mode: fullscreen)').matches
        );
      }

      function syncLoginStandalonePwaClass() {
        const on = isLoginStandalonePwa();
        document.documentElement.classList.toggle('ios-standalone-pwa', on);
        document.getElementById('loginScreen')?.classList.toggle('lp-standalone-pwa', on);
        return on;
      }

      function setLoginPortalScrollLock(on) {
        const root = document.documentElement;
        const body = document.body;
        if (on) {
          _loginPortalScrollY = window.scrollY || 0;
          applyLoginStableViewport();
          root.classList.add('login-portal-open');
          body.classList.add('login-portal-open');
          body.style.top = _loginPortalScrollY ? `-${_loginPortalScrollY}px` : '';
          body.style.left = '0';
          body.style.right = '0';
          body.style.width = '100%';
          syncLoginPortalChromePaint();
          syncLoginViewportLayout();
          window.scrollTo(0, 0);
        } else {
          root.classList.remove('login-portal-open');
          body.classList.remove('login-portal-open');
          body.style.top = '';
          body.style.left = '';
          body.style.right = '';
          body.style.width = '';
          clearLoginPortalViewportState();
          syncLoginPortalChromePaint();
          window.scrollTo(0, _loginPortalScrollY);
        }
      }

      /** جوال: تثبيت الشاشة + منع سحب الصفحة عند الكيبورد */
      function initLoginScreenViewportLock() {
        if (window._loginVpLockBound) return;
        window._loginVpLockBound = true;
        syncLoginStandalonePwaClass();
        document.addEventListener(
          'touchmove',
          (e) => {
            if (window._mrPtrPulling) return;
            if (!document.body.classList.contains('login-portal-open')) return;
            if (!isLoginMobileViewport()) return;
            if (e.target?.closest?.('#loginCard input, #loginCard textarea, #loginCard select')) return;
            e.preventDefault();
          },
          { passive: false, capture: true }
        );
        document.addEventListener(
          'focusin',
          (e) => {
            if (!document.body.classList.contains('login-portal-open')) return;
            const field = e.target?.closest?.('#loginCard input, #loginCard textarea, #loginCard select');
            if (!field) return;
            scheduleLoginFieldScroll(field);
          },
          true
        );
        document.addEventListener(
          'focusout',
          () => {
            setTimeout(resetLoginScreenScrollIfKeyboardClosed, 0);
            setTimeout(resetLoginScreenScrollIfKeyboardClosed, 120);
            setTimeout(resetLoginScreenScrollIfKeyboardClosed, 320);
          },
          true
        );
        const vv = window.visualViewport;
        if (vv && !window._loginVvBound) {
          window._loginVvBound = true;
          const onVvChange = () => {
            if (!document.body.classList.contains('login-portal-open')) return;
            syncLoginViewportLayout();
            window.scrollTo(0, 0);
            const field = document.activeElement?.closest?.('#loginCard input, #loginCard textarea, #loginCard select');
            if (field) scheduleLoginFieldScroll(field);
            else resetLoginScreenScrollIfKeyboardClosed();
          };
          vv.addEventListener('resize', onVvChange, { passive: true });
          vv.addEventListener('scroll', onVvChange, { passive: true });
        }
        if (!window._loginOrientationBound) {
          window._loginOrientationBound = true;
          window.addEventListener('orientationchange', () => {
            _loginLockedVpH = 0;
            setTimeout(() => {
              applyLoginStableViewport();
              syncLoginViewportLayout();
              const field = document.activeElement?.closest?.('#loginCard input, #loginCard textarea, #loginCard select');
              if (field) scheduleLoginFieldScroll(field);
              else resetLoginScreenScrollIfKeyboardClosed();
            }, 100);
          });
        }
        window.addEventListener('resize', () => {
          if (!document.body.classList.contains('login-portal-open')) return;
          syncLoginViewportLayout();
          const field = document.activeElement?.closest?.('#loginCard input, #loginCard textarea, #loginCard select');
          if (field) scheduleLoginFieldScroll(field);
        }, { passive: true });
      }

      function openLoginPortal() {
        const ls = document.getElementById('loginScreen');
        const app = document.getElementById('appWrap');
        setNativeAppShellActive(false);
        syncLoginStandalonePwaClass();
        probeLoginSafeBottom();
        setLoginPortalScrollLock(true);
        syncLoginScreenFloor();
        if (ls) {
          ls.classList.remove('hidden');
          ls.removeAttribute('hidden');
          ls.setAttribute('aria-hidden', 'false');
          ls.scrollTop = 0;
          resetLoginCardShift();
          requestAnimationFrame(() => {
            syncLoginViewportLayout();
            window.scrollTo(0, 0);
          });
        }
        document.querySelector('#loginScreen #loginCard .wefaq-logo-slot')
          ?.querySelectorAll(':scope > .wefaq-app-logo, :scope > img')
          .forEach((el) => el.remove());
        if (typeof syncWefaqBranding === 'function') syncWefaqBranding();
        if (app) {
          app.style.display = 'none';
          app.classList.remove('rbac-ready');
        }
      }

      function closeLoginPortal() {
        const ls = document.getElementById('loginScreen');
        const app = document.getElementById('appWrap');
        if (ls) {
          const focused = document.activeElement;
          if (focused && ls.contains(focused) && typeof focused.blur === 'function') {
            focused.blur();
          }
          ls.classList.add('hidden');
          ls.setAttribute('hidden', '');
          ls.setAttribute('aria-hidden', 'true');
        }
        setLoginPortalScrollLock(false);
        if (app) {
          app.classList.add('rbac-ready');
          app.style.display = '';
        }
        setNativeAppShellActive(true);
        if (typeof syncLoginStandalonePwaClass === 'function') syncLoginStandalonePwaClass();
        if (typeof syncWefaqBranding === 'function') syncWefaqBranding();
        if (typeof initSidebarMobileControls === 'function') {
          requestAnimationFrame(() => initSidebarMobileControls());
        }
        if (typeof syncMobileBottomNavLayout === 'function') {
          requestAnimationFrame(() => syncMobileBottomNavLayout());
        }
        if (typeof syncMobilePlatformScale === 'function') {
          requestAnimationFrame(() => syncMobilePlatformScale());
        }
      }

      async function showLoginPageTransition() {
        const el = document.getElementById('loginTransition');
        if (!el) return;
        if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
          await new Promise(r => setTimeout(r, 350));
          return;
        }
        el.classList.add('is-visible');
        await new Promise(r => setTimeout(r, 1500));
        el.classList.remove('is-visible');
      }

      const ATHAR_WELCOME_SEEN_KEY = 'athar_welcome_seen';
      const ATHAR_WELCOME_SHINE_MS = 4800;
      const ATHAR_WELCOME_HOLD_MS = 900;
      const ATHAR_WELCOME_EXIT_MS = 700;

      function shouldSkipAtharWelcomeSplash() {
        try {
          if (sessionStorage.getItem(ATHAR_WELCOME_SEEN_KEY) === '1') return true;
          if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return true;
          const hash = window.location.hash || '';
          if (hash.includes('type=recovery') || hash.includes('reset-password') || hash.includes('access_token')) return true;
        } catch (_) {}
        return false;
      }

      function finishAtharWelcomeSplash(splash) {
        try { sessionStorage.setItem(ATHAR_WELCOME_SEEN_KEY, '1'); } catch (_) {}
        document.documentElement.classList.remove('aws-booting');
        if (splash) splash.remove();
      }

      async function playAtharWelcomeSplash() {
        const splash = document.getElementById('atharWelcomeSplash');
        if (!splash || shouldSkipAtharWelcomeSplash()) {
          finishAtharWelcomeSplash(splash);
          return;
        }

        const logo = splash.querySelector('.aws-brand-logo');
        if (!logo) {
          finishAtharWelcomeSplash(splash);
          return;
        }

        splash.removeAttribute('hidden');
        splash.setAttribute('aria-hidden', 'false');
        document.documentElement.classList.add('aws-booting');

        await new Promise((r) => requestAnimationFrame(() => requestAnimationFrame(r)));

        const reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
        if (reduceMotion) {
          splash.classList.add('aws-active');
          await new Promise((r) => setTimeout(r, 350));
        } else {
          splash.classList.add('aws-active');
          await new Promise((r) => setTimeout(r, ATHAR_WELCOME_SHINE_MS));
        }

        await new Promise((r) => setTimeout(r, reduceMotion ? 350 : ATHAR_WELCOME_HOLD_MS));
        splash.classList.add('aws-exiting');
        await new Promise((r) => setTimeout(r, reduceMotion ? 200 : ATHAR_WELCOME_EXIT_MS));
        finishAtharWelcomeSplash(splash);
      }

      let _mrSessionRestoreGuard = null;

      function finishSessionRestoreBoot() {
        if (_mrSessionRestoreGuard) {
          clearTimeout(_mrSessionRestoreGuard);
          _mrSessionRestoreGuard = null;
        }
        document.documentElement.classList.add('mr-boot-ready');
        document.documentElement.classList.remove('mr-session-restore');
      }

      function cancelSessionRestoreBoot() {
        if (_mrSessionRestoreGuard) {
          clearTimeout(_mrSessionRestoreGuard);
          _mrSessionRestoreGuard = null;
        }
        document.documentElement.classList.remove('mr-session-restore', 'mr-boot-ready');
      }

      function armSessionRestoreGuard(ms = 12000) {
        if (_mrSessionRestoreGuard) clearTimeout(_mrSessionRestoreGuard);
        _mrSessionRestoreGuard = setTimeout(() => {
          _mrSessionRestoreGuard = null;
          if (!document.documentElement.classList.contains('mr-session-restore')) return;
          if (isMirsadDebugLog()) console.warn('[boot] session restore guard — forcing UI visible');
          finishSessionRestoreBoot();
          if (!state.currentUser) {
            try {
              openLoginPortal();
              showLoginForm();
            } catch (_) {}
          }
        }, ms);
      }

      async function enterGuestBrowse() {
        if (isPublicDeployHost()) {
          showToast('على الرابط المنشور سجّل الدخول بحسابك الرسمي — وضع «متابعة كضيف» لا يجلب البيانات من القاعدة.', 'warning');
          return;
        }
        hideLoginError();
        // بدون جلسة، طلبات PostgREST تمر كـ anon وغالباً RLS تمنع القراءة → جداول فارغة.
        // تسجيل دخول مجهول يعطي JWT بدور authenticated (يحتاج تفعيله من Supabase → Authentication → Providers → Anonymous).
        try {
          const { error: anonErr } = await sb.auth.signInAnonymously();
          if (anonErr) {
            if (isMirsadDebugLog()) console.warn('[Guest] Anonymous sign-in:', anonErr.message);
            showToast('تنبيه الضيف: فعّل «Anonymous sign-ins» في Supabase وحدّث سياسات RLS للقراءة، وإلا ستظهر المنصة بدون بيانات.', 'warning');
          }
        } catch (e) {
          if (isMirsadDebugLog()) console.warn('[Guest] signInAnonymously', e);
        }
        await onUserAuthenticated(GUEST_LOCAL_PROFILE);
      }

      function toggleLoginPw() {
        const inp = document.getElementById('loginPassword');
        const ico = document.getElementById('loginPwIcon');
        if (!inp) return;
        inp.type = inp.type === 'password' ? 'text' : 'password';
        ico.className = inp.type === 'password' ? 'fas fa-eye' : 'fas fa-eye-slash';
      }

      const PASSWORD_RESET_EMAIL_KEY = 'athar_password_reset_email';
      const PASSWORD_RECOVERY_PENDING_KEY = 'athar_password_recovery_uid';
      let passwordResetEmail = '';

      function markPasswordRecoveryPending(userId) {
        if (!userId) return;
        try { localStorage.setItem(PASSWORD_RECOVERY_PENDING_KEY, String(userId)); } catch (_) { /* noop */ }
      }

      function isPasswordRecoveryPending(userId) {
        if (!userId) return false;
        try { return localStorage.getItem(PASSWORD_RECOVERY_PENDING_KEY) === String(userId); } catch (_) { return false; }
      }

      function clearPasswordRecoveryPending() {
        try { localStorage.removeItem(PASSWORD_RECOVERY_PENDING_KEY); } catch (_) { /* noop */ }
      }

      async function abandonPasswordRecovery() {
        clearPasswordRecoveryPending();
        try { await atharSignOut(); } catch (_) { /* noop */ }
      }

      async function showLoginFormFromPasswordRecovery() {
        await abandonPasswordRecovery();
        showLoginForm();
      }

      function normalizeRecoveryCode(value) {
        return String(value || '').replace(/\D/g, '').slice(0, 8);
      }

      function rememberPasswordResetEmail(email) {
        passwordResetEmail = Sec.normalizeEmail(email || '');
        try {
          if (passwordResetEmail) sessionStorage.setItem(PASSWORD_RESET_EMAIL_KEY, passwordResetEmail);
          else sessionStorage.removeItem(PASSWORD_RESET_EMAIL_KEY);
        } catch (_) { /* noop */ }
      }

      function getPasswordResetEmail() {
        if (passwordResetEmail) return passwordResetEmail;
        try {
          const stored = Sec.normalizeEmail(sessionStorage.getItem(PASSWORD_RESET_EMAIL_KEY) || '');
          if (stored) passwordResetEmail = stored;
        } catch (_) { /* noop */ }
        return passwordResetEmail;
      }

      function clearPasswordResetEmail() {
        const email = getPasswordResetEmail();
        rememberPasswordResetEmail('');
        clearPasswordResetResendStorage(email);
        stopPasswordResetResendCountdown();
        updatePasswordResetResendButton({ enabled: true });
      }

      function showLoginForm() {
        const lc = document.getElementById('loginCard');
        if (!lc) return;
        lc.style.display = '';
        const fc = document.getElementById('forgotCard');
        const oc = document.getElementById('otpCard');
        const rc = document.getElementById('resetCard');
        if (fc) fc.style.display = 'none';
        if (oc) oc.style.display = 'none';
        if (rc) rc.style.display = 'none';
        hideLoginError();
        stopPasswordResetResendCountdown();
      }

      function showForgotPassword() {
        const lc = document.getElementById('loginCard');
        if (!lc) return;
        lc.style.display = 'none';
        const fc = document.getElementById('forgotCard');
        const oc = document.getElementById('otpCard');
        const rc = document.getElementById('resetCard');
        if (fc) fc.style.display = '';
        if (oc) oc.style.display = 'none';
        if (rc) rc.style.display = 'none';
        hideLoginError();
      }

      function showOtpForm(email) {
        const lc = document.getElementById('loginCard');
        if (!lc) return;
        const resetEmail = Sec.normalizeEmail(email || getPasswordResetEmail());
        if (resetEmail) rememberPasswordResetEmail(resetEmail);
        lc.style.display = 'none';
        const fc = document.getElementById('forgotCard');
        const oc = document.getElementById('otpCard');
        const rc = document.getElementById('resetCard');
        if (fc) fc.style.display = 'none';
        if (oc) oc.style.display = '';
        if (rc) rc.style.display = 'none';
        hideLoginError();
        const hint = document.getElementById('otpEmailHint');
        if (hint) hint.textContent = resetEmail || '';
        const msg = document.getElementById('otpSuccessMsg');
        const ok = document.getElementById('otpSuccess');
        if (msg && ok) {
          msg.textContent = passwordResetDeliveryNote(resetEmail);
          ok.classList.add('show');
        }
        setTimeout(() => document.getElementById('resetOtp')?.focus(), 80);
        syncPasswordResetResendUi(resetEmail);
      }

      function showResetForm() {
        const lc = document.getElementById('loginCard');
        if (!lc) return;
        lc.style.display = 'none';
        const fc = document.getElementById('forgotCard');
        const oc = document.getElementById('otpCard');
        const rc = document.getElementById('resetCard');
        if (fc) fc.style.display = 'none';
        if (oc) oc.style.display = 'none';
        if (rc) rc.style.display = '';
        hideLoginError();
        setTimeout(() => document.getElementById('newPassword')?.focus(), 80);
      }

      function showLoginError(msg) {
        const el = document.getElementById('loginError');
        if (!el) {
          showToast(msg || 'خطأ', 'warning');
          return;
        }
        document.getElementById('loginErrorMsg').textContent = msg;
        el.classList.add('show');
      }
      function hideLoginError() {
        document.getElementById('loginError')?.classList.remove('show');
        document.getElementById('forgotError')?.classList.remove('show');
        document.getElementById('forgotSuccess')?.classList.remove('show');
        document.getElementById('otpError')?.classList.remove('show');
        document.getElementById('otpSuccess')?.classList.remove('show');
        document.getElementById('resetError')?.classList.remove('show');
      }

      function setLoginLoading(loading, btnId = 'loginBtn', defaultHTML = '<span>تسجيل الدخول</span>') {
        const btn = document.getElementById(btnId);
        if (!btn) return;
        if (loading) {
          btn.disabled = true;
          btn.innerHTML = '<span class="lp-btn-spin" aria-hidden="true"></span>';
        } else {
          btn.disabled = false;
          btn.innerHTML = defaultHTML;
        }
      }

      // ───────────────────────────────────────────────────────────────────────────
      // LOGIN
      // ───────────────────────────────────────────────────────────────────────────
      /** iOS: إخفاء مقترحات لوحة المفاتيح في خانة المستخدم (QuickType / إكمال تلقائي) */
      function initLoginIosIdentifierNoSuggest(idEl) {
        if (!idEl || idEl.dataset.iosNoSuggest === '1') return;
        idEl.dataset.iosNoSuggest = '1';
        const isIOS =
          /iPad|iPhone|iPod/i.test(navigator.userAgent) ||
          (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
        if (!isIOS) return;
        idEl.setAttribute('readonly', 'readonly');
        const unlock = () => idEl.removeAttribute('readonly');
        idEl.addEventListener('focus', unlock, { once: true });
        idEl.addEventListener('touchstart', unlock, { once: true, passive: true });
      }

      /** تقليل شريط iOS + Enter بين الحقول */
      function initLoginFieldKeyboard() {
        const idEl = document.getElementById('loginIdentifier');
        const pwEl = document.getElementById('loginPassword');
        if (!idEl || !pwEl || idEl.dataset.kbBound === '1') return;
        idEl.dataset.kbBound = '1';
        initLoginIosIdentifierNoSuggest(idEl);
        pwEl.addEventListener('touchstart', () => scheduleLoginFieldScroll(pwEl), { passive: true });
        idEl.addEventListener('keydown', (e) => {
          if (e.key !== 'Enter') return;
          e.preventDefault();
          pwEl.focus();
        });
        pwEl.addEventListener('keydown', (e) => {
          if (e.key === 'Enter') {
            e.preventDefault();
            handleLogin();
          }
        });
        const loginBtn = document.getElementById('loginBtn');
        if (loginBtn && loginBtn.dataset.clickBound !== '1') {
          loginBtn.dataset.clickBound = '1';
          loginBtn.addEventListener('click', (e) => {
            e.preventDefault();
            handleLogin();
          });
        }
      }

      async function handleLogin() {
        if (!document.getElementById('loginIdentifier')) {
          showToast('تسجيل الدخول من الواجهة غير متاح.', 'info');
          return;
        }
        hideLoginError();
        const identifier = document.getElementById('loginIdentifier').value.trim();
        const password = document.getElementById('loginPassword').value;

        if (!identifier) return showLoginError('يرجى إدخال الرقم الوظيفي أو البريد الإلكتروني');
        if (!password) return showLoginError('يرجى إدخال كلمة المرور');

        setLoginLoading(true);

        try {
          // تحديد الإيميل (إذا كان المُدخَل رقم وظيفي)
          let email = identifier;
          if (!identifier.includes('@')) {
            const { data, error } = await sb.rpc('get_email_by_emp_number', { emp_num: identifier });
            if (error) throw error;
            if (!data) {
              showLoginError('الرقم الوظيفي غير مسجل');
              setLoginLoading(false);
              return;
            }
            email = data;
          }
          email = Sec.normalizeEmail(email);

          // تسجيل الدخول
          const { data: authData, error: authErr } = await sb.auth.signInWithPassword({ email, password });
          if (authErr) {
            showLoginError('البريد أو كلمة المرور غير صحيحة');
            setLoginLoading(false);
            return;
          }

          // جلب الملف الشخصي
          const { data: profile, error: pErr } = await sb
            .from('users').select('*').eq('auth_uid', authData.user.id).maybeSingle();

          if (pErr) throw pErr;
          if (!profile) {
            showLoginError('لم يتم العثور على ملف شخصي - تواصل مع الإدارة');
            await atharSignOut();
            setLoginLoading(false);
            return;
          }

          if (!profile.is_active) {
            showLoginError('حسابك معطّل - تواصل مع الإدارة');
            await atharSignOut();
            setLoginLoading(false);
            return;
          }

          setLoginLoading(false);
          await showLoginPageTransition();
          await onUserAuthenticated(profile);
          showToast(`مرحباً ${profile.name} 👋`, 'success');
          // طلب الإشعارات عند تسجيل دخول جديد
          try { initAtharWebPush({ promptIfNeeded: true }); } catch (_) { /* noop */ }
        } catch (err) {
          if (isMirsadDebugLog()) console.error('Login error:', formatPostgrestError(err), err);
          showLoginError('خطأ في الاتصال بالخادم. حاول مجدداً.');
          setLoginLoading(false);
        }
      }

      // ───────────────────────────────────────────────────────────────────────────
      // تنشيط واجهة التطبيق بعد تسجيل الدخول
      // ───────────────────────────────────────────────────────────────────────────
      async function onUserAuthenticated(profile) {
        try {
          state._dataLoading = true;
          state._dataReady = false;
          invalidateR2BackendResolution();

          // جلب الفروع التي يشرف عليها المستخدم (المشرف يشرف على منطقة، فنجيب كل فروعها)
          let mySupervisedBranches = [];
          const loadSupervisorBranches = async () => {
            const { data: regions } = await sb.from('regions').select('id').eq('supervisor_id', profile.id);
            const regionIds = (regions || []).map(r => r.id);
            if (!regionIds.length) return;
            const { data: branches } = await sb.from('branches').select('id').in('region_id', regionIds);
            state.currentUser.supervisedBranches = (branches || []).map(b => b.id);
          };
          if (normalizeUserRole(profile.role) === 'supervisor') {
            if (isMobileViewport()) {
              setTimeout(() => loadSupervisorBranches().catch(e => { if (isMirsadDebugLog()) console.warn('[supervisor branches]', e); }), 0);
            } else {
              const { data: regions } = await sb.from('regions').select('id').eq('supervisor_id', profile.id);
              const regionIds = (regions || []).map(r => r.id);
              if (regionIds.length) {
                const { data: branches } = await sb.from('branches').select('id').in('region_id', regionIds);
                mySupervisedBranches = (branches || []).map(b => b.id);
              }
            }
          }

          const normRole = normalizeUserRole(profile.role);
          state.currentUser = {
            ...profile,
            role: normRole,
            supervisedBranches: mySupervisedBranches,
            color: ROLE_COLORS[normRole] || '#6b7280',
            initial: (profile.name || 'م').charAt(0)
          };

          loadTheme();
          await loadRolePermissions();
          await loadProfileAvatars();
          warmAvatarPresetUrlCache().catch(() => {});
          applyRBACUI({ skipCmpRefresh: true });
          armSessionRestoreGuard();
          startLiveClock();
          const clockOk = await initKsaClockSync();
          if (!clockOk) showToast('تعذّر مزامنة وقت الرياض — إعادة المحاولة…', 'warning');
          if (ksaClockReady()) {
            ksaInitViewState(ntDpState);
            ksaInitViewState(cmpDpState);
            ksaInitViewState(dpState);
          }

          const finishLoginBoot = () => {
            ensureActiveTabAllowed();
            setLoginLoading(false);

            const startRealtime = () => {
              try {
                setupRealtime();
              } catch (e) {
                if (isMirsadDebugLog()) console.warn('[Realtime] تعذّر بدء الاشتراك:', e);
                syncMobilePermissionsFallbackPoll();
              }
            };
            if (typeof requestIdleCallback === 'function') {
              requestIdleCallback(startRealtime, { timeout: 3000 });
            } else {
              setTimeout(startRealtime, 0);
            }

            if (state._autoForwardTimer) clearInterval(state._autoForwardTimer);
            state._autoForwardTimer = null;

            // مزامنة إشعارات Web Push عند كل فتح للتطبيق (بعد تحميل البيانات)
            setTimeout(() => {
              bootAtharWebPushOnAppOpen().catch((e) => {
                if (isMirsadDebugLog()) console.warn('[webPush] app open boot', e);
              });
            }, 1200);

            try { maybeOpenTicketFromPushUrl(); } catch (_) { /* noop */ }
            try { maybeOpenBroadcastFromPushUrl(); } catch (_) { /* noop */ }

            if (state._notifTimer) clearInterval(state._notifTimer);
            state._notifTimer = setInterval(() => {
              if (document.hidden) return;
              renderNotifBadge();
            }, 30 * 1000);

            if (state._scoreTimer) clearInterval(state._scoreTimer);
            state._scoreTimer = setInterval(() => {
              if (document.hidden) return;
              if (document.getElementById('tab-dashboard')?.classList.contains('active')) {
                renderPersonalIndicators();
              }
              if (document.getElementById('tab-compliance')?.classList.contains('active')) {
                renderCompliance();
              }
            }, 60 * 1000);

            renderNotifBadge();
          };

          const runInitialRender = () => {
            try {
              renderAll();
            } catch (renderErr) {
              if (isMirsadDebugLog()) console.error('renderAll', renderErr);
              showToast('تعذّر عرض بعض أقسام الواجهة. راجع وحدة التحكم للتفاصيل.', 'error');
            }
          };

          const revealAppShell = () => {
            goToSavedOrDefaultTab({});
            closeLoginPortal();
            updateSidebarUser();
            showGlobalLoader(false);
            finishSessionRestoreBoot();
          };

          revealAppShell();
          const dataOk = await loadAllData();
          if (!dataOk) {
            throw new Error('تعذّر تحميل البيانات من Supabase (انظر رسالة الخطأ السابقة أو Console).');
          }
          state._seeAllCompliancePrev = canSeeAllCompliance();
          state._viewAllTicketsPrev = canViewAllTickets();
          await Promise.all([cmpReloadGeoDataIfNeeded()]);
          state._wfViolationsScope = canViewAllTickets();
          cmpRefreshAfterPermissionChange();
          wfRefreshAfterPermissionChange();
          runInitialRender();
          finishLoginBoot();
        } catch (err) {
          if (isMirsadDebugLog()) console.error('onUserAuthenticated', err);
          showGlobalLoader(false);
          cancelSessionRestoreBoot();
          try { await atharSignOut(); } catch (_) { /* noop */ }
          state.currentUser = null;
          document.getElementById('appWrap')?.classList.remove('rbac-ready');
          try {
            openLoginPortal();
            showLoginForm();
          } catch (_) { /* noop */ }
          setLoginLoading(false);
          showToast('تعذّر إكمال تسجيل الدخول: ' + (err && err.message ? err.message : String(err)), 'error');
        }
      }

      // ───────────────────────────────────────────────────────────────────────────
      // LOGOUT
      // ───────────────────────────────────────────────────────────────────────────
      /** خروج محلي فقط — لا يستدعي /auth/v1/logout (يتجنّب 403 عند جلسة منتهية أو ممسوحة مسبقاً) */
      async function atharSignOut() {
        try {
          await sb.auth.signOut({ scope: 'local' });
        } catch (_) { /* noop */ }
      }

      async function handleLogout() {
        const onProfilePage = isProfilePageOpen();
        if (!await confirmDialog('هل تريد تسجيل الخروج؟', { type: 'info', title: 'تسجيل الخروج', okText: 'خروج' })) return;
        if (onProfilePage) syncProfilePageShell(false);

        // إلغاء كل قنوات الـ realtime
        stopMobilePermissionsFallbackPoll();
        state.realtimeChannels.forEach(ch => sb.removeChannel(ch));
        state.realtimeChannels = [];

        // إيقاف المؤقتات
        if (state._autoForwardTimer) { clearInterval(state._autoForwardTimer); state._autoForwardTimer = null; }
        if (state._notifTimer) { clearInterval(state._notifTimer); state._notifTimer = null; }
            if (state._scoreTimer) { clearInterval(state._scoreTimer); state._scoreTimer = null; }

        try { await disableAtharWebPush({ silent: true }); } catch (_) { /* noop */ }

        // حذف session التبويب الحالي فقط (مو كل التبويبات!)
        const scopeId = sessionStorage.getItem(AUTH_SCOPE_SESSION_KEY) || sessionStorage.getItem('tab_id');
        if (scopeId) {
          Object.keys(localStorage).forEach(key => {
            if (key.startsWith(scopeId + '_')) {
              localStorage.removeItem(key);
            }
          });
          sessionStorage.removeItem(AUTH_SCOPE_SESSION_KEY);
          sessionStorage.removeItem('tab_id');
          if (localStorage.getItem('last_tab_id') === scopeId) localStorage.removeItem('last_tab_id');
          if (localStorage.getItem('last_auth_scope') === scopeId) localStorage.removeItem('last_auth_scope');
        }

        state.currentUser = null;
        state.users = [];
        state.branches = [];
        state.violations = [];
        state.violationTypes = [];
        state.notifications = [];
        state.broadcastInbox = [];
        state._readNotifsSet = null;
        invalidateNotifCache();
        state._dismissedNotifsSet = null;
        state._dbDismissedNotifIds = null;
        state._dataLoading = false;
        state._dataReady = false;

        invalidateR2BackendResolution();

        try { await atharSignOut(); } catch (_) { }

        openLoginPortal();
        showLoginForm();
        showToast('تم تسجيل الخروج. سجّل الدخول للمتابعة.', 'info');
      }

      // ───────────────────────────────────────────────────────────────────────────
      // FORGOT PASSWORD
      // ───────────────────────────────────────────────────────────────────────────
      async function handleForgotPassword() {
        if (!document.getElementById('forgotEmail')) {
          showToast('استعادة كلمة المرور غير متاحة من الواجهة.', 'info');
          return;
        }
        hideLoginError();
        const email = Sec.normalizeEmail(document.getElementById('forgotEmail').value);
        if (!email || !Sec.isEmail(email)) {
          document.getElementById('forgotError').classList.add('show');
          document.getElementById('forgotErrorMsg').textContent = 'الايميل غير صحيح أو غير مسجل في المنصة';
          return;
        }

        setLoginLoading(true, 'forgotBtn', '<i class="fas fa-paper-plane"></i><span>إرسال الرمز</span>');

        try {
          const { data: isRegistered, error: checkErr } = await sb.rpc('check_platform_email_for_reset', {
            p_email: email
          });
          if (checkErr) throw checkErr;
          if (!isRegistered) {
            document.getElementById('forgotError').classList.add('show');
            document.getElementById('forgotErrorMsg').textContent = 'الايميل غير صحيح أو غير مسجل في المنصة';
            return;
          }

          await requestPasswordResetEmail(email);

          rememberPasswordResetEmail(email);
          showOtpForm(email);
        } catch (err) {
          if (isMirsadDebugLog()) console.error('[ForgotPassword]', err);
          document.getElementById('forgotError').classList.add('show');
          document.getElementById('forgotErrorMsg').textContent = formatForgotPasswordError(err);
        } finally {
          setLoginLoading(false, 'forgotBtn', '<i class="fas fa-paper-plane"></i><span>إرسال الرمز</span>');
        }
      }

      async function handleResendPasswordCode() {
        hideLoginError();
        const resendBtn = document.getElementById('otpResendBtn');
        if (resendBtn?.getAttribute('aria-disabled') === 'true') return;
        const email = getPasswordResetEmail();
        const errEl = document.getElementById('otpError');
        const errMsg = document.getElementById('otpErrorMsg');
        if (!email || !Sec.isEmail(email)) {
          if (errEl && errMsg) {
            errEl.classList.add('show');
            errMsg.textContent = 'ارجع واكتب الايميل المسجل في المنصة أولاً';
          }
          return;
        }

        setLoginLoading(true, 'otpBtn', '<i class="fas fa-check"></i><span>تحقق من الرمز</span>');
        try {
          await requestPasswordResetEmail(email);
          const ok = document.getElementById('otpSuccess');
          const okMsg = document.getElementById('otpSuccessMsg');
          if (ok && okMsg) {
            ok.classList.add('show');
            okMsg.textContent = passwordResetDeliveryNote(email);
          }
          document.getElementById('resetOtp').value = '';
          document.getElementById('resetOtp')?.focus();
          await syncPasswordResetResendUi(email);
        } catch (err) {
          if (isMirsadDebugLog()) console.error('[ResendPasswordCode]', err);
          if (errEl && errMsg) {
            errEl.classList.add('show');
            errMsg.textContent = formatForgotPasswordError(err);
          }
          const waitSeconds = err?.blocked
            ? 0
            : (Number(err.waitSeconds) || parsePasswordResetErrorWaitSeconds(err) || ((err?.status === 429 || /rate limit|429/i.test(String(err?.message || ''))) ? 60 : 0));
          if (err?.blocked) {
            stopPasswordResetResendCountdown();
            clearPasswordResetResendStorage(email);
            updatePasswordResetResendButton({ enabled: false, blocked: true });
          } else if (waitSeconds > 0) {
            startPasswordResetResendCountdown(email, waitSeconds);
          } else {
            await syncPasswordResetResendUi(email);
          }
        } finally {
          setLoginLoading(false, 'otpBtn', '<i class="fas fa-check"></i><span>تحقق من الرمز</span>');
        }
      }

      async function handleVerifyResetCode() {
        if (!document.getElementById('resetOtp')) {
          showToast('التحقق من الرمز غير متاح من الواجهة.', 'info');
          return;
        }
        hideLoginError();
        const email = getPasswordResetEmail();
        const code = normalizeRecoveryCode(document.getElementById('resetOtp').value);
        const errEl = document.getElementById('otpError');
        const errMsg = document.getElementById('otpErrorMsg');

        if (!email || !Sec.isEmail(email)) {
          errEl.classList.add('show');
          errMsg.textContent = 'ارجع واكتب الايميل المسجل في المنصة أولاً';
          return;
        }
        if (code.length !== 8) {
          errEl.classList.add('show');
          errMsg.textContent = 'أدخل الرمز المكوّن من 8 خانات';
          return;
        }

        setLoginLoading(true, 'otpBtn', '<i class="fas fa-check"></i><span>تحقق من الرمز</span>');
        try {
          const { data, error } = await sb.auth.verifyOtp({
            email,
            token: code,
            type: 'recovery'
          });
          if (error) throw error;
          if (data?.session?.user?.id) markPasswordRecoveryPending(data.session.user.id);
          showResetForm();
        } catch (err) {
          if (isMirsadDebugLog()) console.error('[VerifyResetCode]', err);
          errEl.classList.add('show');
          errMsg.textContent = 'الرمز غير صحيح أو منتهي الصلاحية. تأكد من آخر رمز وصلك على البريد.';
        } finally {
          setLoginLoading(false, 'otpBtn', '<i class="fas fa-check"></i><span>تحقق من الرمز</span>');
        }
      }

      // ───────────────────────────────────────────────────────────────────────────
      // RESET PASSWORD
      // ───────────────────────────────────────────────────────────────────────────
      async function handleResetPassword() {
        if (!document.getElementById('newPassword')) {
          showToast('تعيين كلمة المرور غير متاح من الواجهة.', 'info');
          return;
        }
        hideLoginError();
        const newPw = document.getElementById('newPassword').value;
        const conf = document.getElementById('confirmPassword').value;

        const errEl = document.getElementById('resetError');
        const errMsg = document.getElementById('resetErrorMsg');

        if (!newPw || newPw.length < 8) {
          errEl.classList.add('show');
          errMsg.textContent = 'كلمة المرور يجب أن تكون 8 أحرف على الأقل';
          return;
        }
        if (newPw !== conf) {
          errEl.classList.add('show');
          errMsg.textContent = 'كلمتا المرور غير متطابقتين';
          return;
        }

        setLoginLoading(true, 'resetBtn', '<i class="fas fa-check"></i><span>تعيين كلمة المرور</span>');

        try {
          const { error } = await sb.auth.updateUser({ password: newPw });
          if (error) throw error;

          const resetEmail = getPasswordResetEmail();
          if (resetEmail) {
            try { await sb.rpc('clear_password_reset_attempts', { p_email: resetEmail }); } catch (_) { /* noop */ }
          }

          clearPasswordRecoveryPending();
          try { await atharSignOut(); } catch (_) { /* noop */ }
          showToast('تم تحديث كلمة المرور بنجاح ✓', 'success');
          clearPasswordResetEmail();
          history.replaceState(null, '', window.location.pathname);
          showLoginForm();
          document.getElementById('newPassword').value = '';
          document.getElementById('confirmPassword').value = '';
        } catch (err) {
          errEl.classList.add('show');
          errMsg.textContent = 'فشل التحديث: ' + (err.message || 'الرابط منتهي الصلاحية');
        } finally {
          setLoginLoading(false, 'resetBtn', '<i class="fas fa-check"></i><span>تعيين كلمة المرور</span>');
        }
      }

      // ───────────────────────────────────────────────────────────────────────────
      // التحقق من جلسة سابقة + معالجة رابط reset password
      // ───────────────────────────────────────────────────────────────────────────
      async function tryDevAutoLogin() {
        if (!DEV_AUTO_LOGIN) return false;
        const email = (DEV_ADMIN_EMAIL || '').trim();
        const password = (DEV_ADMIN_PASSWORD || '').trim();
        if (!email || !password) return false;
        try {
          const { error } = await sb.auth.signInWithPassword({
            email: Sec.normalizeEmail(email),
            password
          });
          if (error) {
            if (isMirsadDebugLog()) console.warn('[DEV] Auto login:', error.message);
            return false;
          }
          const { data: { session } } = await sb.auth.getSession();
          if (!session?.user) return false;
          const { data: profile } = await sb
            .from('users').select('*').eq('auth_uid', session.user.id).maybeSingle();
          if (profile && profile.is_active) {
            await onUserAuthenticated(profile);
            showToast('وضع التطوير: تسجيل دخول تلقائي', 'info');
            return true;
          }
          await atharSignOut();
          if (isMirsadDebugLog()) console.warn('[DEV] Auto login: لا يوجد مستخدم نشط مرتبط بهذا الحساب');
          return false;
        } catch (e) {
          if (isMirsadDebugLog()) console.warn('[DEV] Auto login:', e);
          return false;
        }
      }

      function initPwaSessionPersistence() {
        if (window._mrPwaSessionBound) return;
        window._mrPwaSessionBound = true;

        const resumeAuthIfNeeded = async () => {
          if (!isStandalonePwaShell()) return;
          const app = document.getElementById('appWrap');
          if (!app || app.style.display === 'none') return;
          if (state.currentUser) return;
          try {
            const { data: { session } } = await sb.auth.getSession();
            if (!session?.user) return;
            if (isPasswordRecoveryPending(session.user.id)) return;
            const { data: profile } = await sb
              .from('users').select('*').eq('auth_uid', session.user.id).maybeSingle();
            if (profile?.is_active) {
              await onUserAuthenticated(profile);
            }
          } catch (e) {
            if (isMirsadDebugLog()) console.warn('[PWA resume]', e);
          }
        };

        document.addEventListener('visibilitychange', () => {
          if (!document.hidden) resumeAuthIfNeeded();
        });
        window.addEventListener('pageshow', () => {
          resumeAuthIfNeeded();
        });
      }

      async function checkExistingSession() {
        armSessionRestoreGuard();
        const hash = window.location.hash;
        if (hash.includes('access_token') || hash.includes('type=recovery')) {
          await new Promise(r => setTimeout(r, 450));
        }

        if (hash.includes('type=recovery') || hash.includes('reset-password')) {
          cancelSessionRestoreBoot();
          const { data: { session: recoverySession } } = await sb.auth.getSession();
          if (recoverySession?.user?.id) markPasswordRecoveryPending(recoverySession.user.id);
          openLoginPortal();
          showResetForm();
          return;
        }

        const { data: { session } } = await sb.auth.getSession();
        if (!session?.user) {
          clearPasswordRecoveryPending();
        } else if (isPasswordRecoveryPending(session.user.id)) {
          cancelSessionRestoreBoot();
          openLoginPortal();
          showResetForm();
          return;
        } else {
          const { data: profile } = await sb
            .from('users').select('*').eq('auth_uid', session.user.id).maybeSingle();

          if (profile && profile.is_active) {
            await onUserAuthenticated(profile);
            return;
          }
          await atharSignOut();
        }

        if (await tryDevAutoLogin()) return;

        cancelSessionRestoreBoot();
        openLoginPortal();
        showLoginForm();
      }

      // ═══════════════════════════════════════════════════════════════════════════
      // 8. DATA LOADING
      // ═══════════════════════════════════════════════════════════════════════════

      /** بعد تسجيل الدخول: يوضح إن كانت RLS تمنع القراءة */
      async function showDataAccessDiagnosis() {
        const u = state.currentUser;
        if (!u?.auth_uid) return;
        const role = u.role || '?';
        const checks = await Promise.all([
          sb.from('regions').select('id').limit(1),
          sb.from('violations').select('id').limit(1),
        ]);
        const [regRes, violRes] = checks;
        const regErr = regRes.error?.message || '';
        const violErr = violRes.error?.message || '';
        const regOk = (regRes.data || []).length;
        const violOk = (violRes.data || []).length;
        let msg = `دورك: ${role}. `;
        if (regErr || violErr) {
          msg += [regErr && `regions: ${regErr}`, violErr && `violations: ${violErr}`].filter(Boolean).join(' · ');
        } else if (!regOk && !violOk) {
          msg += 'الجلسة سليمة لكن RLS تمنع قراءة الجداول — شغّل supabase/تحقق-من-البيانات.sql و supabase/إصلاح-قراءة-المدير.sql في SQL Editor.';
        } else {
          msg += 'القراءة تعمل جزئياً — قد يكون دورك يرى بيانات محدودة فقط.';
        }
        if (isPublicDeployHost()) {
          msg += ' تأكد من Authentication → URL Configuration في Supabase: ' + location.origin + location.pathname;
        }
        showToast(msg, 'warning');
        if (isMirsadDebugLog()) console.warn('[DataAccess]', { role, regRes, violRes });
      }

      async function loadAllData(isRetry) {
        const mobLoad = isMobileViewport();
        await ensureAuthSessionReady(2000);

        state._dataLoading = true;
        if (document.getElementById('tab-compliance')?.classList.contains('active')) {
          try { renderCompliance(); } catch (_) { /* noop */ }
        }

        const _loadT0 = (typeof performance !== 'undefined' && performance.now) ? performance.now() : Date.now();
        let loaderGuard;
        setConnStatus('reconnecting');
        try {
          const VIOLATIONS_LIMIT = getViolationsFetchLimit();
          const VIOLATION_LIST_SELECT_LOCAL = VIOLATION_LIST_SELECT;

          const fetchAll = Promise.all([
            sb.from('regions').select(DESKTOP_REGION_SELECT).order('name'),
            sb.from('branches').select(mobLoad ? 'id,name,region_id' : DESKTOP_BRANCH_SELECT).order('name'),
            sb.from('users').select(mobLoad ? MOB_USER_SELECT : DESKTOP_USER_SELECT).order('name'),
            sb.from('violations').select(VIOLATION_LIST_SELECT_LOCAL).order('created_at', { ascending: false }).limit(VIOLATIONS_LIMIT),
            sb.from('violation_types').select(mobLoad ? MOB_VIOLATION_TYPES_SELECT : DESKTOP_VIOLATION_TYPES_SELECT).order('name'),
            !state.currentUser?.id
              ? Promise.resolve({ data: [], error: null })
              : sb.from('notifications')
                .select('id,event_key,title,message,type,icon,ticket_id,scope,broadcast_id,broadcast_kind,is_auto,is_read,created_at,dismissed_at,broadcasts(expires_at)')
                .eq('user_id', state.currentUser.id)
                .is('dismissed_at', null)
                .order('created_at', { ascending: false })
                .limit(mobLoad ? 40 : 80),
            mobLoad || !state.currentUser?.id
              ? Promise.resolve({ data: [], error: null })
              : Promise.resolve({ data: [], error: null }),
            mobLoad || !state.currentUser?.id
              ? Promise.resolve({ data: [], error: null })
              : sb.from('user_notif_dismissals')
                .select('notif_id')
                .eq('user_id', state.currentUser.id)
                .limit(500),
          ]);

          let pack;
          const mobTimeout = isRetry ? 48000 : 42000;
          try {
            pack = mobLoad
              ? await withLoadTimeout(fetchAll, mobTimeout, 'انتهت مهلة تحميل البيانات — تحقق من إنترنت الجوال')
              : await fetchAll;
          } catch (timeoutErr) {
            if (mobLoad && !isRetry && /مهلة|timeout/i.test(timeoutErr.message || '')) {
              showToast('بطء الشبكة — إعادة المحاولة…', 'info');
              return loadAllData(true);
            }
            throw timeoutErr;
          }

          let [
            { data: regions, error: rErr },
            { data: branches, error: bErr },
            { data: users, error: uErr },
            { data: violations, error: vErr },
            { data: vTypes, error: vtErr },
            { data: notifs, error: nErr },
            { data: broadcastInbox, error: biErr },
            { data: notifDismissals, error: ndErr },
          ] = pack;

          if (rErr) throw rErr;
          if (bErr) throw bErr;
          if (vErr) throw vErr;

          if (uErr && mobLoad) {
            if (isMirsadDebugLog()) console.warn('[DataLoad mobile] users, fallback partial', uErr);
            try {
              users = await loadUsersForMobileViolations(violations || [], mobTimeout);
              uErr = null;
              showToast('تم تحميل مستخدمي التذاكر فقط — الشبكة بطيئة.', 'warning');
            } catch (partialErr) {
              if (isMirsadDebugLog()) console.warn('[DataLoad mobile] partial users failed', partialErr);
            }
          }
          if (uErr) throw uErr;
          if (vtErr) {
            if (isMirsadDebugLog()) console.warn('[DataLoad] violation_types:', formatPostgrestError(vtErr), vtErr);
            if (mobLoad) {
              try {
                const retry = await sb.from('violation_types').select('id,name,category,severity,weight').order('name');
                if (!retry.error && retry.data?.length) {
                  vTypes = retry.data;
                  vtErr = null;
                }
              } catch (_) { /* noop */ }
            }
          }
          if (nErr && isMirsadDebugLog()) console.warn('[DataLoad] notifications:', nErr.message, nErr);
          if (biErr && isMirsadDebugLog()) console.warn('[DataLoad] broadcast_inbox:', biErr.message, biErr);
          if (ndErr && isMirsadDebugLog()) console.warn('[DataLoad] user_notif_dismissals:', ndErr.message, ndErr);

          const _ms = Math.round(((typeof performance !== 'undefined' && performance.now) ? performance.now() : Date.now()) - _loadT0);
          if (isMirsadDebugLog()) {
            console.log(`[DataLoad] Loaded ${violations?.length || 0} violations from Supabase (${_ms}ms).`);
            if (_ms > 8000) {
              console.warn('[Perf] تحميل البيانات أبطأ من المتوقع — راجع Network (طلبات REST إلى Supabase) وحجم أعمدة JSON في الجداول.');
            }
            if (violations && violations.length === 0) {
              console.info('[DataLoad] لا توجد مخالفات بعد — جرّب «رصد مخالفة» من القائمة. إن كان الجدول فيه بيانات ولا تظهر هنا فالمشكلة من صلاحيات القاعدة وليس من الكود.');
            }
          }

          state.regions = regions || [];
          state.branches = branches || [];
          state.users = users || [];
          rebuildLookupMaps();
          const enrichRow = mobLoad ? enrichViolationLite : enrichViolation;
          state.violations = (violations || []).map(enrichRow);
          state.violationTypes = vTypes || [];
          invalidateEmpScoreCache();
          state.notifications = notifs || [];
          state.broadcastInbox = mobLoad ? [] : (broadcastInbox || []);
          state._dbDismissedNotifIds = mobLoad
            ? new Set()
            : new Set((notifDismissals || []).map(r => r.notif_id).filter(Boolean));
          state._dismissedNotifsSet = null;
          invalidateNotifCache();
          scheduleBcExpiryUiRefresh();

          const nR = state.regions.length;
          const nB = state.branches.length;
          const nU = state.users.length;
          const nV = state.violations.length;
          if (nR + nB + nU + nV === 0 && !sessionStorage.getItem('dataLoadEmptyWarn')) {
            sessionStorage.setItem('dataLoadEmptyWarn', '1');
            if (state.currentUser?.auth_uid && typeof showDataAccessDiagnosis === 'function') {
              showDataAccessDiagnosis().catch(e => { if (isMirsadDebugLog()) console.warn('[DataAccess]', e); });
            }
            const isGuest = state.currentUser && state.currentUser.id === GUEST_LOCAL_PROFILE.id;
            const isAdmin = !isGuest && state.currentUser && state.currentUser.role === 'admin';
            const guestHint =
              'وضع «متابعة كضيف»: تأكد من تفعيل Anonymous في Supabase (Authentication → Providers → Anonymous). ثم أضف سياسات RLS تسمح بـ SELECT على الجداول العامة (مثل regions, branches, users, violations…) لدور authenticated المجهول، أو سجّل الدخول بحساب حقيقي من الجدول users.';
            const adminHint =
              'حسابك مدير نظام لكن التطبيق لم يستلم أي صف من regions/branches/users/violations. إن كانت الجداول ممتلئة في SQL Editor فالسبب غالباً سياسات RLS تمنع SELECT لهذه الجداول حتى بعد تسجيل الدخول — راجع Policies في Supabase (Table editor → Policies) وطابقة Network في المتصفح لطلبات REST.';
            const normalHint =
              'لم يُجلب أي صف (مناطق/فروع/مستخدمون/مخالفات = 0). تحقق من أن رابط المشروع والمفتاح في أعلى index.html يخصان نفس المشروع، وأن الجداول فيها بيانات، وأن RLS يسمح لدورك بالقراءة (راجع Console وNetwork).';
            const deployHint =
              'على GitHub Pages: سجّل الدخول بالبريد/الرقم الوظيفي وكلمة المرور (ليس «متابعة كضيف»). في Supabase: Authentication → URL Configuration أضف ' +
              (typeof location !== 'undefined' ? location.origin + location.pathname : 'رابط الموقع') +
              ' ثم تأكد أن حسابك في جدول users مربوط بـ auth_uid.';
            const msg = isGuest ? guestHint : (isPublicDeployHost() ? deployHint : (isAdmin ? adminHint : normalHint));
            showToast(msg, 'warning');
          }

          state._dataLoading = false;
          state._dataReady = true;
          state._wfViolationsScope = canViewAllTickets();
          setConnStatus('connected');
          if (mobLoad) showGlobalLoader(false);
          return true;
        } catch (err) {
          state._dataLoading = false;
          if (isMirsadDebugLog()) console.error('Failed to load data:', err);
          setConnStatus('disconnected');
          if (mobLoad) showGlobalLoader(false);
          const msg = formatPostgrestError(err) || (err && err.message) || String(err);
          showToast(
            /مهلة|timeout/i.test(msg)
              ? msg + ' — Wi‑Fi أو 4G ثم حدّث الصفحة'
              : 'فشل تحميل البيانات: ' + msg,
            'error'
          );
          return false;
        } finally {
          if (loaderGuard) clearTimeout(loaderGuard);
          if (mobLoad) mobFinishDashboardRender();
        }
      }

      function setupRealtimeSync() { /* تم دمجها في setupRealtime() لتفادي اشتراك مكرر */ }

      function rebuildLookupMaps() {
        const um = new Map();
        for (const u of (state.users || [])) if (u && u.id) um.set(u.id, u);
        const bm = new Map();
        for (const b of (state.branches || [])) if (b && b.id) bm.set(b.id, b);
        const rm = new Map();
        for (const r of (state.regions || [])) if (r && r.id) rm.set(r.id, r);
        state._userById = um;
        state._branchById = bm;
        state._regionById = rm;
      }

      function sortRegionsLocal() {
        state.regions.sort((a, b) => String(a.name || '').localeCompare(String(b.name || ''), 'ar'));
      }

      function sortBranchesLocal() {
        state.branches.sort((a, b) => String(a.name || '').localeCompare(String(b.name || ''), 'ar'));
      }

      function sortUsersLocal() {
        state.users.sort((a, b) => String(a.name || '').localeCompare(String(b.name || ''), 'ar'));
      }

      function sortViolTypesLocal() {
        state.violationTypes.sort((a, b) => String(a.name || '').localeCompare(String(b.name || ''), 'ar'));
      }

      function upsertLocalRegion(row) {
        if (!row?.id) return;
        const idx = state.regions.findIndex(r => r.id === row.id);
        if (idx >= 0) state.regions[idx] = { ...state.regions[idx], ...row };
        else state.regions.push(row);
        sortRegionsLocal();
        rebuildLookupMaps();
      }

      function removeLocalRegion(id) {
        state.regions = state.regions.filter(r => r.id !== id);
        rebuildLookupMaps();
      }

      function upsertLocalBranch(row) {
        if (!row?.id) return;
        const idx = state.branches.findIndex(b => b.id === row.id);
        if (idx >= 0) state.branches[idx] = { ...state.branches[idx], ...row };
        else state.branches.push(row);
        sortBranchesLocal();
        rebuildLookupMaps();
      }

      function removeLocalBranch(id) {
        state.branches = state.branches.filter(b => b.id !== id);
        rebuildLookupMaps();
      }

      function upsertLocalUser(row) {
        if (!row?.id) return;
        const idx = state.users.findIndex(u => u.id === row.id);
        if (idx >= 0) state.users[idx] = { ...state.users[idx], ...row };
        else state.users.push(row);
        sortUsersLocal();
        rebuildLookupMaps();
      }

      function patchViolationsBranchForEmployee(employeeId, branchId) {
        if (!employeeId) return;
        let touched = false;
        for (const v of state.violations) {
          if (v.employee_id === employeeId && v.branch_id !== branchId) {
            v.branch_id = branchId;
            touched = true;
          }
        }
        if (touched) {
          invalidateEmpScoreCache();
          invalidateNotifCache();
        }
      }

      function upsertLocalViolType(row) {
        if (!row?.id) return;
        const idx = state.violationTypes.findIndex(v => v.id === row.id);
        if (idx >= 0) state.violationTypes[idx] = { ...state.violationTypes[idx], ...row };
        else state.violationTypes.push(row);
        sortViolTypesLocal();
      }

      function removeLocalViolType(id) {
        state.violationTypes = state.violationTypes.filter(v => v.id !== id);
      }

      function isSupStageEntryLog(log) {
        const action = String(log?.action || '');
        if (/رد الموظف/i.test(action)) return true;
        if (/تمرير تلقائي/i.test(action) && /المشرف|بانتظار رد المشرف/i.test(action)) return true;
        if (/تمرير.*للمشرف/i.test(action)) return true;
        return false;
      }

      function resolveSupStartTime(t) {
        const logs = parseDbJsonArray(t?.logs);
        for (let i = logs.length - 1; i >= 0; i--) {
          if (isSupStageEntryLog(logs[i])) return logs[i].date;
        }
        if (t?.state === 'sup' && isDbTruthy(t?.auto_forwarded_emp) && t?.updated_at) {
          return t.updated_at;
        }
        return t?.state === 'sup' ? (t.created_at || null) : null;
      }

      function enrichViolation(t) {
        if (!t) return t;
        t.logs = parseDbJsonArray(t.logs);
        if (!state._userById || !state._branchById || !state._regionById) rebuildLookupMaps();
        const emp = state._userById.get(t.employee_id);
        const sup = state._userById.get(t.supervisor_id);
        const obs = state._userById.get(t.observer_id);
        const br = state._branchById.get(t.branch_id);
        const region = br ? state._regionById.get(br.region_id) : null;

        t._empName = emp?.name || '-';
        t._empNumber = padEmpNum(emp?.employee_number);
        t._supName = sup?.name || '-';
        t._obsName = obs?.name || '-';
        t._branchName = br?.name || '-';
        t._regionName = region?.name || '-';

        if (!t.violation_type_id && t.violation_type && state.violationTypes?.length) {
          const vt = state.violationTypes.find(x => x.name === t.violation_type);
          if (vt) t.violation_type_id = vt.id;
        }

        // ─── حساب وقت دخول حالة المشرف (من السجل) ───
        t._supStartTime = resolveSupStartTime(t);

        return t;
      }

      /**
       * حقول json/jsonb من Supabase قد تُعاد مصفوفة أو **سلسلة JSON**.
       * بدون التحليل، Array.isArray يفشل فيُستبدل المرفقات القديمة بمصفوفة فارغة.
       */
      function parseDbJsonArray(raw) {
        if (raw == null) return [];
        if (Array.isArray(raw)) return [...raw];
        if (typeof raw === 'string') {
          try {
            const p = JSON.parse(raw);
            return Array.isArray(p) ? p : [];
          } catch (_) {
            return [];
          }
        }
        return [];
      }

      // ═══════════════════════════════════════════════════════════════════════════
      // 9. REALTIME SUBSCRIPTIONS (محسّنة: تحديث محلي بدل إعادة تحميل كاملة)
      // ═══════════════════════════════════════════════════════════════════════════

      // Debounce لتجميع تحديثات متتالية وتقليل re-renders
      function debounce(fn, ms = 250) {
        let timer;
        return (...args) => {
          clearTimeout(timer);
          timer = setTimeout(() => fn(...args), ms);
        };
      }

      function hasDesktopSessionLock() {
        return true;
      }

      function isNativeMobileShell() {
        return !!(window.matchMedia('(display-mode: standalone)').matches
          || window.navigator.standalone
          || document.referrer.includes('android-app://'));
      }

      function isTabletDevice() {
        if (typeof navigator === 'undefined') return false;
        return /iPad/i.test(navigator.userAgent)
          || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1)
          || (/Android/i.test(navigator.userAgent) && !/Mobile/i.test(navigator.userAgent));
      }

      const MR_VIEWPORT_DEVICE = 'width=device-width, initial-scale=1, maximum-scale=1, minimum-scale=1, user-scalable=no, viewport-fit=cover, interactive-widget=overlays-content';

      function buildTabletLandscapeViewportContent() {
        const layoutW = 992;
        const landW = Math.max(window.screen?.width || 0, window.screen?.height || 0) || window.innerWidth || layoutW;
        const scale = Math.max(0.85, Math.min(1.35, landW / layoutW));
        const scaleStr = (Math.round(scale * 10000) / 10000).toFixed(4);
        return `width=${layoutW}, initial-scale=${scaleStr}, maximum-scale=${scaleStr}, minimum-scale=${scaleStr}, user-scalable=no, viewport-fit=cover, interactive-widget=overlays-content`;
      }

      function needsTabletMobileViewportLock() {
        if (!document.documentElement.classList.contains('mr-mobile-ui')) return false;
        if (!isTabletDevice()) return false;
        return window.matchMedia('(orientation: landscape)').matches;
      }

      function syncMobileLayoutViewport() {
        const meta = document.querySelector('meta[name="viewport"]');
        if (!meta) return false;
        const lock = needsTabletMobileViewportLock();
        document.documentElement.classList.toggle('mr-tablet-landscape', lock);
        const next = lock ? buildTabletLandscapeViewportContent() : MR_VIEWPORT_DEVICE;
        const prev = meta.getAttribute('content') || '';
        if (prev === next) return false;
        meta.setAttribute('content', next);
        return true;
      }

      function isDesktopUi() {
        return !isMobileViewport();
      }

      function syncDesktopUiClass() {
        const desktop = isDesktopUi();
        document.documentElement.classList.toggle('mr-desktop-ui', desktop);
        document.documentElement.classList.toggle('mr-mobile-ui', !desktop);
        const viewportChanged = typeof syncMobileLayoutViewport === 'function' && syncMobileLayoutViewport();
        if (typeof window.syncPlatformDesktopStylesheets === 'function') {
          window.syncPlatformDesktopStylesheets(desktop);
        }
        if (!desktop) {
          const sb = document.getElementById('sidebar');
          if (sb) {
            sb.classList.remove('open', 'sidebar-rail-open', 'sidebar-rail-hover', 'sidebar-rail-expanded');
            delete sb.dataset.railExpanded;
            delete sb.dataset.railHover;
            sb.style.removeProperty('width');
            sb.style.removeProperty('min-width');
            sb.style.removeProperty('flex');
            sb.style.removeProperty('max-width');
          }
          document.getElementById('sidebarOverlay')?.classList.remove('open');
          const mobNav = document.getElementById('mobileBottomNav');
          if (mobNav) mobNav.style.removeProperty('display');
        }
        if (viewportChanged && typeof window.initMobileViewportSync === 'function') {
          window.dispatchEvent(new Event('resize'));
        }
      }

      function isMobileViewport() {
        if (typeof window === 'undefined') return false;
        // كشف iPad بدقة: userAgent + maxTouchPoints (يعمل حتى على iPad Chrome)
        const isIpadOrTablet =
          /iPad/i.test(navigator.userAgent) ||
          (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1) ||
          (/Android/i.test(navigator.userAgent) && !/Mobile/i.test(navigator.userAgent));
        if (isIpadOrTablet) return true;
        const isWide = window.matchMedia('(min-width: 993px)').matches;
        const isTouch = window.matchMedia('(pointer: coarse)').matches;
        // كمبيوتر/لابتوب حقيقي (فأرة + hover) يبقى واجهة كمبيوتر مهما ضاق العرض
        const isRealDesktop = window.matchMedia('(hover: hover) and (pointer: fine)').matches;
        return isTouch || (!isRealDesktop && !isWide);
      }

      function initMobilePullToRefresh() {
        if (window._mrMobilePtrBound) return;
        window._mrMobilePtrBound = true;

        const PTR_THRESHOLD = 72;
        const PTR_MAX = 88;
        const PTR_ACTIVATE = 10;
        let startY = 0;
        let pulling = false;
        let ptrPending = false;
        let refreshing = false;
        let scrollRoot = null;
        let pullPx = 0;

        const ptr = document.createElement('div');
        ptr.id = 'mrMobilePtr';
        ptr.setAttribute('aria-hidden', 'true');
        ptr.innerHTML = '<div class="mr-ptr-spinner" aria-hidden="true"></div>';
        document.body.appendChild(ptr);

        function getPtrMode() {
          if (document.body.classList.contains('login-portal-open')) return 'login';
          if (typeof isNotifPageOpen === 'function' && isNotifPageOpen()) return 'notif';
          return 'app';
        }

        function syncNotifPtrTop() {
          const head = document.querySelector('#tab-notifications .notif-page-head');
          if (!head) return;
          document.documentElement.style.setProperty('--mr-notif-ptr-top', head.getBoundingClientRect().bottom + 'px');
        }

        function setNotifPtrActive(on) {
          document.documentElement.classList.toggle('mr-notif-ptr-active', on);
          if (on) syncNotifPtrTop();
          else document.documentElement.style.removeProperty('--mr-notif-ptr-top');
        }

        function getPtrHosts() {
          return {
            appWrap: document.getElementById('appWrap'),
            login: document.getElementById('loginScreen'),
            notifTab: document.getElementById('tab-notifications'),
          };
        }

        function setPtrDrag(on) {
          const mode = getPtrMode();
          const { appWrap, login, notifTab } = getPtrHosts();
          appWrap?.classList.toggle('mr-ptr-drag', mode === 'app' && on);
          login?.classList.toggle('mr-ptr-drag', mode === 'login' && on);
          notifTab?.classList.toggle('mr-ptr-drag', mode === 'notif' && on);
          if (mode === 'notif') setNotifPtrActive(on || refreshing);
          else setNotifPtrActive(false);
          if (on) {
            appWrap?.classList.remove('mr-ptr-snap');
            login?.classList.remove('mr-ptr-snap');
            notifTab?.classList.remove('mr-ptr-snap');
            ptr.classList.remove('mr-ptr-snap');
          }
        }

        function snapPtrBack() {
          const mode = getPtrMode();
          const { appWrap, login, notifTab } = getPtrHosts();
          appWrap?.classList.remove('mr-ptr-drag');
          login?.classList.remove('mr-ptr-drag');
          notifTab?.classList.remove('mr-ptr-drag');
          if (mode === 'login') login?.classList.add('mr-ptr-snap');
          else if (mode === 'notif') {
            notifTab?.classList.add('mr-ptr-snap');
            setNotifPtrActive(true);
          } else appWrap?.classList.add('mr-ptr-snap');
          ptr.classList.add('mr-ptr-snap');
          setPull(0);
          window.setTimeout(() => {
            appWrap?.classList.remove('mr-ptr-snap');
            login?.classList.remove('mr-ptr-snap');
            ptr.classList.remove('mr-ptr-snap');
          }, 320);
        }

        function ptrEnabled() {
          return document.documentElement.classList.contains('mr-mobile-ui') || (typeof isMobileViewport === 'function' && isMobileViewport());
        }

        function isPtrBlocked() {
          if (refreshing) return true;
          if (document.querySelector('.modal.open, .confirm-overlay.open, #confirmOverlay[style*="flex"]')) return true;
          if (document.body.classList.contains('ticket-sheet-open')) return true;
          if (document.body.classList.contains('aws-booting')) return true;
          const splash = document.getElementById('atharWelcomeSplash');
          if (splash && !splash.hasAttribute('hidden')) return true;
          return false;
        }

        function isScrollable(el) {
          if (!el || el === document.body || el === document.documentElement) return false;
          const style = getComputedStyle(el);
          const oy = style.overflowY;
          return oy === 'auto' || oy === 'scroll' || oy === 'overlay';
        }

        function isDocumentScrollRoot(root) {
          return !root || root === document.scrollingElement || root === document.documentElement || root === document.body;
        }

        function findScrollRoot(target) {
          let node = target instanceof Element ? target : null;
          while (node && node !== document.body) {
            if (isScrollable(node)) return node;
            node = node.parentElement;
          }
          const usersList = document.querySelector('#tab-departments.active #usersList.users-grid--mob-list');
          if (usersList && isScrollable(usersList)) return usersList;
          const notifList = document.querySelector('#tab-notifications #notifPageList.notif-list--page');
          if (notifList && isScrollable(notifList) && typeof isNotifPageOpen === 'function' && isNotifPageOpen()) return notifList;
          const activeList = document.querySelector('.main #ticketList, .main #reportList');
          if (activeList) {
            const body = activeList.querySelector('.wf-mob-tickets-body');
            if (body && isScrollable(body)) return body;
          }
          const main = document.querySelector('#appWrap .main');
          if (main && isScrollable(main)) return main;
          const login = document.getElementById('loginScreen');
          if (login && !login.hidden && isScrollable(login)) return login;
          return document.scrollingElement || document.documentElement;
        }

        function getScrollTop(root) {
          if (!root) return 0;
          if (isDocumentScrollRoot(root)) {
            return window.scrollY || document.documentElement.scrollTop || 0;
          }
          return root.scrollTop || 0;
        }

        function cancelPtrGesture() {
          window._mrPtrPulling = false;
          pulling = false;
          ptrPending = false;
          scrollRoot = null;
          setPtrDrag(false);
          ptr.classList.remove('mr-ptr-visible', 'mr-ptr-ready', 'mr-ptr-snap');
          setPull(0);
          const { appWrap, login, notifTab } = getPtrHosts();
          appWrap?.classList.remove('mr-ptr-snap', 'mr-ptr-drag');
          login?.classList.remove('mr-ptr-snap', 'mr-ptr-drag');
          notifTab?.classList.remove('mr-ptr-snap', 'mr-ptr-drag');
          setNotifPtrActive(false);
        }

        function resetPull() {
          cancelPtrGesture();
          snapPtrBack();
        }

        function setPull(px) {
          pullPx = Math.max(0, Math.min(PTR_MAX, px));
          document.documentElement.style.setProperty('--mr-ptr-pull', pullPx + 'px');
          const progress = Math.min(1, pullPx / PTR_THRESHOLD);
          document.documentElement.style.setProperty('--mr-ptr-spinner-o', String(Math.min(1, pullPx / 28)));
          document.documentElement.style.setProperty('--mr-ptr-spinner-s', String(0.45 + progress * 0.55));
          ptr.classList.toggle('mr-ptr-visible', pullPx > 4);
          ptr.classList.toggle('mr-ptr-ready', pullPx >= PTR_THRESHOLD);
          if (pullPx > 0) setPtrDrag(true);
        }

        function resetPullImmediate() {
          cancelPtrGesture();
        }

        async function performMobilePullRefresh() {
          const loginOpen = document.body.classList.contains('login-portal-open');
          const appWrap = document.getElementById('appWrap');
          const appShown = appWrap && appWrap.style.display !== 'none';
          if (loginOpen || !appShown) {
            location.reload();
            return;
          }
          if (typeof isNotifPageOpen === 'function' && isNotifPageOpen()) {
            const jobs = [];
            if (typeof refreshPermissionsFromCloud === 'function') {
              jobs.push(refreshPermissionsFromCloud({ forceCloud: true }));
            }
            if (typeof refreshNotificationsFromDb === 'function') {
              jobs.push(refreshNotificationsFromDb());
            }
            await Promise.allSettled(jobs);
            if (typeof renderNotifications === 'function') renderNotifications(true);
            if (typeof flushPermissionsMobileShell === 'function') flushPermissionsMobileShell();
            return;
          }
          const jobs = [];
          if (typeof refreshPermissionsFromCloud === 'function') {
            jobs.push(refreshPermissionsFromCloud({ forceCloud: true }));
          }
          if (typeof refreshNotificationsFromDb === 'function') {
            jobs.push(refreshNotificationsFromDb());
          }
          await Promise.allSettled(jobs);
          const tab = typeof getActiveTabKey === 'function' ? getActiveTabKey() : null;
          if (tab && typeof goTab === 'function') {
            const btn = typeof getNavButtonForTab === 'function' ? getNavButtonForTab(tab) : null;
            goTab(tab, btn, { force: true });
          } else if (typeof flushPermissionsMobileShell === 'function') {
            flushPermissionsMobileShell();
          }
        }

        function finishRefresh() {
          refreshing = false;
          ptr.classList.remove('mr-ptr-refreshing');
          resetPull();
        }

        function triggerRefresh() {
          if (refreshing) return;
          refreshing = true;
          pulling = false;
          ptrPending = false;
          window._mrPtrPulling = false;
          setPtrDrag(true);
          ptr.classList.add('mr-ptr-refreshing', 'mr-ptr-visible');
          setPull(PTR_THRESHOLD);
          performMobilePullRefresh()
            .catch(() => { try { location.reload(); } catch (_) {} })
            .finally(() => setTimeout(finishRefresh, 650));
        }

        // Pull-to-refresh logic disabled by user request but structure kept for app stability.
        let touchDirectionLocked = false;

        document.addEventListener('touchstart', (e) => {
          if (refreshing) return;
          if (e.touches.length !== 1) return;
          if (e.target?.closest?.('.modal, .confirm-overlay, [data-no-ptr], input, textarea, select, .dp-popup, .att-viewer, .td-mob-sheet, .users-io-menu, .wf-status-menu')) return;
          
          scrollRoot = findScrollRoot(e.target);
          startY = e.touches[0].clientY;
          pulling = false;
          ptrPending = false; // Disabled
          touchDirectionLocked = false;
          window._mrPtrPulling = false;
          pullPx = 0;
          setPull(0);
        }, { passive: true, capture: true });

        document.addEventListener('touchmove', (e) => {
          // Logic disabled to prevent refresh but allowing event to pass through
          if (pulling) {
            cancelPtrGesture();
          }
        }, { passive: true, capture: true });

        document.addEventListener('touchend', () => {
          cancelPtrGesture();
          ptrPending = false;
          pulling = false;
        }, { passive: true, capture: true });

        document.addEventListener('touchcancel', resetPullImmediate, { passive: true, capture: true });
      }

      const ATHAR_LOGO_VER = 'new-logo-401';
      const ATHAR_LOGO_SRC = 'icons/athar-logo-v401.png';
      const ATHAR_DECO_SHIFT = { x: -8, y: -210 }; /* الدخول / الانتقال / الشريط (الإزاحة العمودية للشريط عبر CSS) */
      const ATHAR_LOGO_R_DX = { default: -8 };
      const ATHAR_LOGO_R_DY = { default: 2 };
      const ATHAR_LOGO_TEXT_Y = { default: 250, login: 392 };
      const ATHAR_LOGO_VIEWBOX = '-31 75 903 555';
      const ATHAR_LOGO_VIEWBOX_LOGIN = '-31 220 903 370';

      /** شعار ATHAR — الدخول / الانتقال / الشريط */
      function atharWordmarkLogoHtml(decoShift = ATHAR_DECO_SHIFT, rDx = ATHAR_LOGO_R_DX.default, rDy = ATHAR_LOGO_R_DY.default, textY = ATHAR_LOGO_TEXT_Y.default, viewBox = ATHAR_LOGO_VIEWBOX) {
        const dx = decoShift.x;
        const dy = decoShift.y;
        const decoTag = ` data-deco-shift="${dx},${dy}" data-r-dx="${rDx}" data-r-dy="${rDy}" data-text-y="${textY}" data-view-box="${viewBox}"`;
        return `<img src="${ATHAR_LOGO_SRC}" alt="ATHAR" role="img" class="wefaq-app-logo wefaq-app-logo--athar wefaq-app-logo--athar-img" data-athar-ver="${ATHAR_LOGO_VER}"${decoTag} aria-hidden="true" draggable="false" decoding="async">`;
      }

      const ATHAR_LOGO_HOSTS = [
        '#loginScreen #loginCard .wefaq-logo-slot',
        '#loginTransition .wefaq-logo-slot',
        '#brandArea .brand-icon.wefaq-logo-slot'
      ];

      function tuneLoginAtharLogo(host) {
        return;
      }

      function clearLoginAtharLogoTune(host) {
        return;
      }

      function syncAtharBranding() {
        ATHAR_LOGO_HOSTS.forEach((sel) => {
          const host = document.querySelector(sel);
          if (!host) return;
          const rDx = ATHAR_LOGO_R_DX.default;
          const rDy = ATHAR_LOGO_R_DY.default;
          const isLoginLogo = sel.includes('loginCard') || sel.includes('loginTransition');
          const loginDesk = isLoginLogo && !isMobileViewport();
          const loginMob = isLoginLogo && isMobileViewport();
          const textY = loginMob ? ATHAR_LOGO_TEXT_Y.login : ATHAR_LOGO_TEXT_Y.default;
          const viewBox = loginDesk ? ATHAR_LOGO_VIEWBOX_LOGIN : ATHAR_LOGO_VIEWBOX;
          const decoShift = ATHAR_DECO_SHIFT;
          const loginCtx = isLoginLogo ? (loginMob ? 'mob' : 'desk') : 'brand';
          const existing = host.querySelector(':scope > .wefaq-app-logo--athar');
          const decoShiftKey = `${decoShift.x},${decoShift.y}`;
          if (existing?.dataset.atharVer === ATHAR_LOGO_VER &&
            existing.dataset.decoShift === decoShiftKey &&
            existing.dataset.rDx === String(rDx) &&
            existing.dataset.rDy === String(rDy) &&
            existing.dataset.textY === String(textY) &&
            existing.dataset.viewBox === viewBox &&
            existing.dataset.loginCtx === loginCtx) {
            if (loginDesk) tuneLoginAtharLogo(host);
            else if (loginMob) clearLoginAtharLogoTune(host);
            return;
          }
          host.classList.add('wefaq-logo-host');
          host.querySelector(':scope > .brand-mono')?.remove();
          host.querySelectorAll(':scope > .wefaq-app-logo, :scope > img').forEach((el) => el.remove());
          host.insertAdjacentHTML('beforeend', atharWordmarkLogoHtml(decoShift, rDx, rDy, textY, viewBox));
          const freshLogo = host.querySelector(':scope > .wefaq-app-logo--athar');
          if (freshLogo) freshLogo.dataset.loginCtx = loginCtx;
          if (loginDesk) tuneLoginAtharLogo(host);
          else if (loginMob) clearLoginAtharLogoTune(host);
        });
      }

      const syncWefaqBranding = syncAtharBranding;

      const renderAllDebounced = debounce(() => renderAll(), 200);
      const renderAllDebouncedMob = debounce(() => renderAll(), 750);

      function scheduleRenderAll() {
        (isMobileViewport() ? renderAllDebouncedMob : renderAllDebounced)();
      }

      /**
       * تطبيق تغيير من Realtime على state محلياً (بدون استدعاء قاعدة البيانات)
       * @param {Array} list - مرجع المصفوفة في state
       * @param {Object} payload - حدث Realtime
       * @param {Function} enrich - دالة اختيارية لإثراء العنصر
       */
      function applyRealtimeChange(list, payload, enrich) {
        const { eventType, new: newRow, old: oldRow } = payload;
        if (eventType === 'INSERT' && newRow) {
          // تجنّب الإدراج المكرر (لو حدث محلي سبق Realtime)
          if (!list.find(r => r.id === newRow.id)) {
            list.unshift(enrich ? enrich(newRow) : newRow);
          }
        } else if (eventType === 'UPDATE' && newRow) {
          const idx = list.findIndex(r => r.id === newRow.id);
          if (idx >= 0) list[idx] = enrich ? enrich(newRow) : newRow;
          else list.unshift(enrich ? enrich(newRow) : newRow);
        } else if (eventType === 'DELETE' && oldRow) {
          const idx = list.findIndex(r => r.id === oldRow.id);
          if (idx >= 0) list.splice(idx, 1);
        }
      }

      /** تحديث تذكرة واحدة في الذاكرة بعد RPC/إجراء — بدون loadAllData */
      function patchViolationLocally(violationId, patch) {
        if (!violationId || !patch || typeof patch !== 'object') return null;
        const idx = state.violations.findIndex(v => v.id === violationId);
        if (idx < 0) return null;
        const merged = {
          ...state.violations[idx],
          ...patch,
          updated_at: patch.updated_at || new Date().toISOString(),
        };
        const enrichFn = isMobileViewport() ? enrichViolationLite : enrichViolation;
        state.violations[idx] = enrichFn(merged);
        invalidateEmpScoreCache();
        invalidateNotifCache();
        return state.violations[idx];
      }

      /** إعادة رسم الواجهة بعد تحديث محلي لتذكرة */
      function refreshViolationsUI(ticketId) {
        scheduleRenderAll();
        renderNotifications();
        if (!ticketId) return;
        const t = state.violations.find(v => v.id === ticketId);
        if (!t) return;
        if (state.editingTicket?.id === ticketId) {
          state.editingTicket = t;
          if (document.getElementById('ticketModal')?.classList.contains('open')) {
            renderTicketDetailUI(t);
          }
          const viewer = document.getElementById('attViewer');
          if (viewer?.classList.contains('open')) {
            state._attList = parseDbJsonArray(t.attachments);
            renderAttViewer();
          }
        }
      }

      const renderNotifBadgeDebounced = debounce(() => renderNotifBadge(), 400);

      function setupRealtime() {
        state.realtimeChannels.forEach(ch => sb.removeChannel(ch));
        state.realtimeChannels = [];

        const vCh = sb.channel('public:violations')
          .on('postgres_changes', { event: '*', schema: 'public', table: 'violations' }, (payload) => {
            applyRealtimeChange(state.violations, payload, enrichViolation);
            invalidateEmpScoreCache();
            invalidateNotifCache();
            scheduleRenderAll();
            renderNotifBadgeDebounced();
          })
          .subscribe();
        state.realtimeChannels.push(vCh);

        if (!isMobileViewport()) {
          const uCh = sb.channel('public:users')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'users' }, (payload) => {
              applyRealtimeChange(state.users, payload);
              rebuildLookupMaps();
              for (const v of state.violations) enrichViolation(v);
              scheduleRenderAll();
            })
            .subscribe();
          state.realtimeChannels.push(uCh);

          const bCh = sb.channel('public:branches')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'branches' }, (payload) => {
              applyRealtimeChange(state.branches, payload);
              rebuildLookupMaps();
              for (const v of state.violations) enrichViolation(v);
              scheduleRenderAll();
            })
            .subscribe();
          state.realtimeChannels.push(bCh);
        }

        const permKeys = [MR_PERMS_BUNDLE_DB_KEY, MR_PERMS_DB_KEY, MR_USER_PERMS_DB_KEY, MR_PROFILE_AVATARS_DB_KEY];
        state._permsRealtimeSubscribed = false;
        const pCh = sb.channel('public:platform_settings')
          .on('postgres_changes', { event: '*', schema: 'public', table: 'platform_settings' }, (payload) => {
            const key = payload?.new?.key || payload?.old?.key;
            if (!key) return;
            if (key === MR_PROFILE_AVATARS_DB_KEY) {
              loadProfileAvatars({ forceCloud: true })
                .then(() => {
                  warmAvatarPresetUrlCache().catch(() => {});
                  renderProfileAvatarsAdmin();
                  if (state.currentUser) {
                    updateSidebarUser();
                    if (isProfilePageOpen()) renderProfilePage();
                  }
                })
                .catch(e => { if (isMirsadDebugLog()) console.warn('[profile_avatars] realtime refresh', e); });
              return;
            }
            if (!permKeys.includes(key)) return;
            state._seeAllCompliancePrev = undefined;
            state._viewAllTicketsPrev = undefined;
            refreshPermissionsFromCloud({ forceCloud: true })
              .catch(e => { if (isMirsadDebugLog()) console.warn('[permissions] realtime refresh', e); });
          })
          .subscribe((status) => {
            if (status === 'SUBSCRIBED') {
              state._permsRealtimeSubscribed = true;
              stopMobilePermissionsFallbackPoll();
              return;
            }
            if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT' || status === 'CLOSED') {
              state._permsRealtimeSubscribed = false;
              syncMobilePermissionsFallbackPoll();
            }
          });
        state.realtimeChannels.push(pCh);
        setTimeout(() => {
          if (state.currentUser && !state._permsRealtimeSubscribed) syncMobilePermissionsFallbackPoll();
        }, 8000);
      }

      function teardownRealtime() {
        state._permsRealtimeSubscribed = false;
        stopMobilePermissionsFallbackPoll();
        state.realtimeChannels.forEach(ch => sb.removeChannel(ch));
        state.realtimeChannels = [];
      }

      // ═══════════════════════════════════════════════════════════════════════════
      // 10. RBAC (Role-Based Access Control)
      // ═══════════════════════════════════════════════════════════════════════════

