      const ATT_IMG_EXTS = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'svg', 'bmp', 'heic', 'heif', 'tif', 'tiff'];
      const ATT_VID_EXTS = ['mp4', 'mov', 'webm', 'avi', 'mkv', 'm4v', '3gp'];

